"""
Parameterized generator for GH865_pytorch_lightni_6877.

Source PR:    https://github.com/Lightning-AI/pytorch-lightning/pull/6877
Source Issue: https://github.com/Lightning-AI/pytorch-lightning/issues/6876

Seed varies: renames 'accelerator' identifier with suffix across seeds.

Bug: pre-PR state of workspace files contains the bug the PR fixes.
Fix: agent must replicate the PR's changes guided by spec.md.
"""
from __future__ import annotations

import os
from generators.base import TaskGenerator, GeneratedTask


class Generator(TaskGenerator):
    task_id = 'GH865_pytorch_lightni_6877'
    domain = "Real-World GitHub"
    difficulty = "medium"
    languages = ["python"]

    def generate(self, seed: int) -> GeneratedTask:
        tasks_dir = os.path.join(
            os.path.dirname(__file__), "..", "tasks", 'GH865_pytorch_lightni_6877'
        )
        with open(os.path.join(tasks_dir, "spec.md")) as f:
            spec_md = f.read()
        with open(os.path.join(tasks_dir, "brief.md")) as f:
            brief_md = f.read()

        files = self._base_workspace()
        # Apply seed-based renaming to prevent direct memorization
        suffixes = ["", "_alt", "_impl"]
        suffix = suffixes[seed % len(suffixes)]
        if suffix:
            for fpath in list(files.keys()):
                files[fpath] = files[fpath].replace('accelerator', 'accelerator' + suffix)
        # Deep parameterization — consistent cross-seed variation
        from generators.gh_deep_param import deep_rename_symbols, add_realistic_noise
        files = deep_rename_symbols(files, seed, strategy="mixed")
        files = add_realistic_noise(files, seed, noise_level=0.15)
        return GeneratedTask(
            task_id='GH865_pytorch_lightni_6877',
            seed=seed,
            spec_md=spec_md,
            brief_md=brief_md,
            expected={
                "seed": seed,
                "repo": 'Lightning-AI/pytorch-lightning',
                "pr_number": 6877,
                "bug_fixed": True,
            },
            workspace_files=files,
            metadata={
                "difficulty": "medium",
                "category": "Real-World GitHub",
                "source_pr": "https://github.com/Lightning-AI/pytorch-lightning/pull/6877",
            },
        )

    def _base_workspace(self) -> dict[str, str]:
        """Return the pre-PR (buggy) workspace files."""
        return {
            'pytorch_lightning/core/hooks.py': '# Copyright The PyTorch Lightning team.\n#\n# Licensed under the Apache License, Version 2.0 (the "License");\n# you may not use this file except in compliance with the License.\n# You may obtain a copy of the License at\n#\n#     http://www.apache.org/licenses/LICENSE-2.0\n#\n# Unless required by applicable law or agreed to in writing, software\n# distributed under the License is distributed on an "AS IS" BASIS,\n# WITHOUT WARRANTIES OR CONDITIONS OF ANY KIND, either express or implied.\n# See the License for the specific language governing permissions and\n# limitations under the License.\n"""Various hooks to be used in the Lightning code."""\n\nfrom typing import Any, Dict, List, Optional, Union\n\nimport torch\nfrom torch.optim.optimizer import Optimizer\nfrom torch.utils.data import DataLoader\n\nfrom pytorch_lightning.utilities import move_data_to_device, rank_zero_warn\n\n\nclass ModelHooks:\n    """Hooks to be used in LightningModule."""\n\n    def on_fit_start(self) -> None:\n        """\n        Called at the very beginning of fit.\n        If on DDP it is called on every process\n        """\n\n    def on_fit_end(self) -> None:\n        """\n        Called at the very end of fit.\n        If on DDP it is called on every process\n        """\n\n    def on_train_start(self) -> None:\n        """\n        Called at the beginning of training after sanity check.\n        """\n        # do something at the start of training\n\n    def on_train_end(self) -> None:\n        """\n        Called at the end of training before logger experiment is closed.\n        """\n        # do something at the end of training\n\n    def on_validation_start(self) -> None:\n        """\n        Called at the beginning of validation.\n        """\n        # do something at the start of validation\n\n    def on_validation_end(self) -> None:\n        """\n        Called at the end of validation.\n        """\n        # do something at the end of validation\n\n    def on_pretrain_routine_start(self) -> None:\n        """\n        Called at the beginning of the pretrain routine (between fit and train start).\n\n        - fit\n        - pretrain_routine start\n        - pretrain_routine end\n        - training_start\n\n        """\n        # do something at the start of the pretrain routine\n\n    def on_pretrain_routine_end(self) -> None:\n        """\n        Called at the end of the pretrain routine (between fit and train start).\n\n        - fit\n        - pretrain_routine start\n        - pretrain_routine end\n        - training_start\n\n        """\n        # do something at the end of the pretrain routine\n\n    def on_train_batch_start(self, batch: Any, batch_idx: int, dataloader_idx: int) -> None:\n        """\n        Called in the training loop before anything happens for that batch.\n\n        If you return -1 here, you will skip training for the rest of the current epoch.\n\n        Args:\n            batch: The batched data as it is returned by the training DataLoader.\n            batch_idx: the index of the batch\n            dataloader_idx: the index of the dataloader\n        """\n        # do something when the batch starts\n\n    def on_train_batch_end(self, outputs: Any, batch: Any, batch_idx: int, dataloader_idx: int) -> None:\n        """\n        Called in the training loop after the batch.\n\n        Args:\n            outputs: The outputs of training_step_end(training_step(x))\n            batch: The batched data as it is returned by the training DataLoader.\n            batch_idx: the index of the batch\n            dataloader_idx: the index of the dataloader\n        """\n        # do something when the batch ends\n\n    def on_validation_model_eval(self) -> None:\n        """\n        Sets the model to eval during the val loop\n        """\n        self.eval()\n\n    def on_validation_model_train(self) -> None:\n        """\n        Sets the model to train during the val loop\n        """\n        self.train()\n\n    def on_validation_batch_start(self, batch: Any, batch_idx: int, dataloader_idx: int) -> None:\n        """\n        Called in the validation loop before anything happens for that batch.\n\n        Args:\n            batch: The batched data as it is returned by the validation DataLoader.\n            batch_idx: the index of the batch\n            dataloader_idx: the index of the dataloader\n        """\n        # do something when the batch starts\n\n    def on_validation_batch_end(self, outputs: Any, batch: Any, batch_idx: int, dataloader_idx: int) -> None:\n        """\n        Called in the validation loop after the batch.\n\n        Args:\n            outputs: The outputs of validation_step_end(validation_step(x))\n            batch: The batched data as it is returned by the validation DataLoader.\n            batch_idx: the index of the batch\n            dataloader_idx: the index of the dataloader\n        """\n        # do something when the batch ends\n\n    def on_test_batch_start(self, batch: Any, batch_idx: int, dataloader_idx: int) -> None:\n        """\n        Called in the test loop before anything happens for that batch.\n\n        Args:\n            batch: The batched data as it is returned by the test DataLoader.\n            batch_idx: the index of the batch\n            dataloader_idx: the index of the dataloader\n        """\n        # do something when the batch starts\n\n    def on_test_batch_end(self, outputs: Any, batch: Any, batch_idx: int, dataloader_idx: int) -> None:\n        """\n        Called in the test loop after the batch.\n\n        Args:\n            outputs: The outputs of test_step_end(test_step(x))\n            batch: The batched data as it is returned by the test DataLoader.\n            batch_idx: the index of the batch\n            dataloader_idx: the index of the dataloader\n        """\n        # do something when the batch ends\n\n    def on_test_model_train(self) -> None:\n        """\n        Sets the model to train during the test loop\n        """\n        self.train()\n\n    def on_test_model_eval(self) -> None:\n        """\n        Sets the model to eval during the test loop\n        """\n        self.eval()\n\n    def on_predict_model_eval(self) -> None:\n        """\n        Sets the model to eval during the predict loop\n        """\n        self.eval()\n\n    def on_epoch_start(self) -> None:\n        """\n        Called when either of train/val/test epoch begins.\n        """\n        # do something when the epoch starts\n\n    def on_epoch_end(self) -> None:\n        """\n        Called when either of train/val/test epoch ends.\n        """\n        # do something when the epoch ends\n\n    def on_train_epoch_start(self) -> None:\n        """\n        Called in the training loop at the very beginning of the epoch.\n        """\n        # do something when the epoch starts\n\n    def on_train_epoch_end(self, outputs: List[Any]) -> None:\n        """\n        Called in the training loop at the very end of the epoch.\n        """\n        # do something when the epoch ends\n\n    def on_validation_epoch_start(self) -> None:\n        """\n        Called in the validation loop at the very beginning of the epoch.\n        """\n        # do something when the epoch starts\n\n    def on_validation_epoch_end(self, outputs: List[Any]) -> None:\n        """\n        Called in the validation loop at the very end of the epoch.\n        """\n        # do something when the epoch ends\n\n    def on_test_epoch_start(self) -> None:\n        """\n        Called in the test loop at the very beginning of the epoch.\n        """\n        # do something when the epoch starts\n\n    def on_test_epoch_end(self, outputs: List[Any]) -> None:\n        """\n        Called in the test loop at the very end of the epoch.\n        """\n        # do something when the epoch ends\n\n    def on_test_start(self) -> None:\n        """\n        Called at the beginning of testing.\n        """\n        # do something at the start of testing\n\n    def on_test_end(self) -> None:\n        """\n        Called at the end of testing.\n        """\n        # do something at the end of testing\n\n    def on_predict_start(self) -> None:\n        """\n        Called at the beginning of predicting.\n        """\n        # do something at the start of predicting\n\n    def on_predict_end(self) -> None:\n        """\n        Called at the end of predicting.\n        """\n        # do something at the end of predicting\n\n    def on_before_zero_grad(self, optimizer: Optimizer) -> None:\n        """\n        Called after optimizer.step() and before optimizer.zero_grad().\n\n        Called in the training loop after taking an optimizer step and before zeroing grads.\n        Good place to inspect weight information with weights updated.\n\n        This is where it is called::\n\n            for optimizer in optimizers:\n                optimizer.step()\n                model.on_before_zero_grad(optimizer) # < ---- called here\n                optimizer.zero_grad()\n\n        Args:\n            optimizer: The optimizer for which grads should be zeroed.\n        """\n        # do something with the optimizer or inspect it.\n\n    def on_after_backward(self) -> None:\n        """\n        Called in the training loop after loss.backward() and before optimizers do anything.\n        This is the ideal place to inspect or log gradient information.\n\n        Example::\n\n            def on_after_backward(self):\n                # example to inspect gradient information in tensorboard\n                if self.trainer.global_step % 25 == 0:  # don\'t make the tf file huge\n                    for k, v in self.named_parameters():\n                        self.logger.experiment.add_histogram(\n                            tag=k, values=v.grad, global_step=self.trainer.global_step\n                        )\n\n        """\n\n    def on_post_move_to_device(self) -> None:\n        """\n        Called in the ``parameter_validation`` decorator after :meth:`~pytorch_lightning.core.LightningModule.to`\n        is called. This is a good place to tie weights between modules after moving them to a device. Can be\n        used when training models with weight sharing properties on TPU.\n\n        Addresses the handling of shared weights on TPU:\n        https://github.com/pytorch/xla/blob/master/TROUBLESHOOTING.md#xla-tensor-quirks\n\n        Example::\n\n            def on_post_move_to_device(self):\n                self.decoder.weight = self.encoder.weight\n\n        """\n\n    def configure_sharded_model(self) -> None:\n        """\n        Hook to create modules in a distributed aware context. This is useful for when using sharded plugins,\n        where we\'d like to shard the model instantly, which is useful for extremely large models\n        which can save memory and initialization time.\n\n        The accelerator manages whether to call this hook at every given stage.\n        For sharded plugins where model parallelism is required, the hook is usually on called once\n        to initialize the sharded parameters, and not called again in the same process.\n\n        By default for accelerators/plugins that do not use model sharding techniques,\n        this hook is called during each fit/val/test/predict stages.\n        """\n\n\nclass DataHooks:\n    """Hooks to be used for data related stuff."""\n\n    def prepare_data(self) -> None:\n        """\n        Use this to download and prepare data.\n\n        .. warning:: DO NOT set state to the model (use `setup` instead)\n            since this is NOT called on every GPU in DDP/TPU\n\n        Example::\n\n            def prepare_data(self):\n                # good\n                download_data()\n                tokenize()\n                etc()\n\n                # bad\n                self.split = data_split\n                self.some_state = some_other_state()\n\n        In DDP prepare_data can be called in two ways (using Trainer(prepare_data_per_node)):\n\n        1. Once per node. This is the default and is only called on LOCAL_RANK=0.\n        2. Once in total. Only called on GLOBAL_RANK=0.\n\n        Example::\n\n            # DEFAULT\n            # called once per node on LOCAL_RANK=0 of that node\n            Trainer(prepare_data_per_node=True)\n\n            # call on GLOBAL_RANK=0 (great for shared file systems)\n            Trainer(prepare_data_per_node=False)\n\n        This is called before requesting the dataloaders:\n\n        .. code-block:: python\n\n            model.prepare_data()\n                if ddp/tpu: init()\n            model.setup(stage)\n            model.train_dataloader()\n            model.val_dataloader()\n            model.test_dataloader()\n        """\n\n    def setup(self, stage: Optional[str] = None) -> None:\n        """\n        Called at the beginning of fit (train + validate), validate, test, predict, or tune.\n        This is a good hook when you need to build models dynamically or adjust something about them.\n        This hook is called on every process when using DDP.\n\n        Args:\n            stage: either ``\'fit\'``, ``\'validate\'``, ``\'test\'``, or ``\'predict\'``\n\n        Example::\n\n            class LitModel(...):\n                def __init__(self):\n                    self.l1 = None\n\n                def prepare_data(self):\n                    download_data()\n                    tokenize()\n\n                    # don\'t do this\n                    self.something = else\n\n                def setup(stage):\n                    data = Load_data(...)\n                    self.l1 = nn.Linear(28, data.num_classes)\n\n        """\n\n    def teardown(self, stage: Optional[str] = None) -> None:\n        """\n        Called at the end of fit (train + validate), validate, test, predict, or tune.\n\n        Args:\n            stage: either ``\'fit\'``, ``\'validate\'``, ``\'test\'``, or ``\'predict\'``\n        """\n\n    def train_dataloader(self) -> Any:\n        """\n        Implement one or more PyTorch DataLoaders for training.\n\n        Return:\n            Either a single PyTorch :class:`~torch.utils.data.DataLoader` or a collection of these\n            (list, dict, nested lists and dicts). In the case of multiple dataloaders, please see\n            this :ref:`page <multiple-training-dataloaders>`\n\n        The dataloader you return will not be called every epoch unless you set\n        :paramref:`~pytorch_lightning.trainer.Trainer.reload_dataloaders_every_epoch` to ``True``.\n\n        For data processing use the following pattern:\n\n            - download in :meth:`prepare_data`\n            - process and split in :meth:`setup`\n\n        However, the above are only necessary for distributed processing.\n\n        .. warning:: do not assign state in prepare_data\n\n        - :meth:`~pytorch_lightning.trainer.Trainer.fit`\n        - ...\n        - :meth:`prepare_data`\n        - :meth:`setup`\n        - :meth:`train_dataloader`\n\n        Note:\n            Lightning adds the correct sampler for distributed and arbitrary hardware.\n            There is no need to set it yourself.\n\n        Example::\n\n            # single dataloader\n            def train_dataloader(self):\n                transform = transforms.Compose([transforms.ToTensor(),\n                                                transforms.Normalize((0.5,), (1.0,))])\n                dataset = MNIST(root=\'/path/to/mnist/\', train=True, transform=transform,\n                                download=True)\n                loader = torch.utils.data.DataLoader(\n                    dataset=dataset,\n                    batch_size=self.batch_size,\n                    shuffle=True\n                )\n                return loader\n\n            # multiple dataloaders, return as list\n            def train_dataloader(self):\n                mnist = MNIST(...)\n                cifar = CIFAR(...)\n                mnist_loader = torch.utils.data.DataLoader(\n                    dataset=mnist, batch_size=self.batch_size, shuffle=True\n                )\n                cifar_loader = torch.utils.data.DataLoader(\n                    dataset=cifar, batch_size=self.batch_size, shuffle=True\n                )\n                # each batch will be a list of tensors: [batch_mnist, batch_cifar]\n                return [mnist_loader, cifar_loader]\n\n            # multiple dataloader, return as dict\n            def train_dataloader(self):\n                mnist = MNIST(...)\n                cifar = CIFAR(...)\n                mnist_loader = torch.utils.data.DataLoader(\n                    dataset=mnist, batch_size=self.batch_size, shuffle=True\n                )\n                cifar_loader = torch.utils.data.DataLoader(\n                    dataset=cifar, batch_size=self.batch_size, shuffle=True\n                )\n                # each batch will be a dict of tensors: {\'mnist\': batch_mnist, \'cifar\': batch_cifar}\n                return {\'mnist\': mnist_loader, \'cifar\': cifar_loader}\n\n        """\n        rank_zero_warn("`train_dataloader` must be implemented to be used with the Lightning Trainer")\n\n    def test_dataloader(self) -> Union[DataLoader, List[DataLoader]]:\n        r"""\n        Implement one or multiple PyTorch DataLoaders for testing.\n\n        The dataloader you return will not be called every epoch unless you set\n        :paramref:`~pytorch_lightning.trainer.Trainer.reload_dataloaders_every_epoch` to ``True``.\n\n        For data processing use the following pattern:\n\n            - download in :meth:`prepare_data`\n            - process and split in :meth:`setup`\n\n        However, the above are only necessary for distributed processing.\n\n        .. warning:: do not assign state in prepare_data\n\n\n        - :meth:`~pytorch_lightning.trainer.Trainer.fit`\n        - ...\n        - :meth:`prepare_data`\n        - :meth:`setup`\n        - :meth:`train_dataloader`\n        - :meth:`val_dataloader`\n        - :meth:`test_dataloader`\n\n        Note:\n            Lightning adds the correct sampler for distributed and arbitrary hardware.\n            There is no need to set it yourself.\n\n        Return:\n            Single or multiple PyTorch DataLoaders.\n\n        Example::\n\n            def test_dataloader(self):\n                transform = transforms.Compose([transforms.ToTensor(),\n                                                transforms.Normalize((0.5,), (1.0,))])\n                dataset = MNIST(root=\'/path/to/mnist/\', train=False, transform=transform,\n                                download=True)\n                loader = torch.utils.data.DataLoader(\n                    dataset=dataset,\n                    batch_size=self.batch_size,\n                    shuffle=False\n                )\n\n                return loader\n\n            # can also return multiple dataloaders\n            def test_dataloader(self):\n                return [loader_a, loader_b, ..., loader_n]\n\n        Note:\n            If you don\'t need a test dataset and a :meth:`test_step`, you don\'t need to implement\n            this method.\n\n        Note:\n            In the case where you return multiple test dataloaders, the :meth:`test_step`\n            will have an argument ``dataloader_idx`` which matches the order here.\n        """\n\n    def val_dataloader(self) -> Union[DataLoader, List[DataLoader]]:\n        r"""\n        Implement one or multiple PyTorch DataLoaders for validation.\n\n        The dataloader you return will not be called every epoch unless you set\n        :paramref:`~pytorch_lightning.trainer.Trainer.reload_dataloaders_every_epoch` to ``True``.\n\n        It\'s recommended that all data downloads and preparation happen in :meth:`prepare_data`.\n\n        - :meth:`~pytorch_lightning.trainer.Trainer.fit`\n        - ...\n        - :meth:`prepare_data`\n        - :meth:`train_dataloader`\n        - :meth:`val_dataloader`\n        - :meth:`test_dataloader`\n\n        Note:\n            Lightning adds the correct sampler for distributed and arbitrary hardware\n            There is no need to set it yourself.\n\n        Return:\n            Single or multiple PyTorch DataLoaders.\n\n        Examples::\n\n            def val_dataloader(self):\n                transform = transforms.Compose([transforms.ToTensor(),\n                                                transforms.Normalize((0.5,), (1.0,))])\n                dataset = MNIST(root=\'/path/to/mnist/\', train=False,\n                                transform=transform, download=True)\n                loader = torch.utils.data.DataLoader(\n                    dataset=dataset,\n                    batch_size=self.batch_size,\n                    shuffle=False\n                )\n\n                return loader\n\n            # can also return multiple dataloaders\n            def val_dataloader(self):\n                return [loader_a, loader_b, ..., loader_n]\n\n        Note:\n            If you don\'t need a validation dataset and a :meth:`validation_step`, you don\'t need to\n            implement this method.\n\n        Note:\n            In the case where you return multiple validation dataloaders, the :meth:`validation_step`\n            will have an argument ``dataloader_idx`` which matches the order here.\n        """\n\n    def predict_dataloader(self) -> Union[DataLoader, List[DataLoader]]:\n        r"""\n        Implement one or multiple PyTorch DataLoaders for prediction.\n\n        It\'s recommended that all data downloads and preparation happen in :meth:`prepare_data`.\n\n        - :meth:`~pytorch_lightning.trainer.Trainer.fit`\n        - ...\n        - :meth:`prepare_data`\n        - :meth:`train_dataloader`\n        - :meth:`val_dataloader`\n        - :meth:`test_dataloader`\n\n        Note:\n            Lightning adds the correct sampler for distributed and arbitrary hardware\n            There is no need to set it yourself.\n\n        Return:\n            Single or multiple PyTorch DataLoaders.\n\n        Note:\n            In the case where you return multiple prediction dataloaders, the :meth:`predict`\n            will have an argument ``dataloader_idx`` which matches the order here.\n        """\n\n    def on_train_dataloader(self) -> None:\n        """Called before requesting the train dataloader."""\n\n    def on_val_dataloader(self) -> None:\n        """Called before requesting the val dataloader."""\n\n    def on_test_dataloader(self) -> None:\n        """Called before requesting the test dataloader."""\n\n    def on_predict_dataloader(self) -> None:\n        """Called before requesting the predict dataloader."""\n\n    def transfer_batch_to_device(self, batch: Any, device: Optional[torch.device] = None) -> Any:\n        """\n        Override this hook if your :class:`~torch.utils.data.DataLoader` returns tensors\n        wrapped in a custom data structure.\n\n        The data types listed below (and any arbitrary nesting of them) are supported out of the box:\n\n        - :class:`torch.Tensor` or anything that implements `.to(...)`\n        - :class:`list`\n        - :class:`dict`\n        - :class:`tuple`\n        - :class:`torchtext.data.batch.Batch`\n\n        For anything else, you need to define how the data is moved to the target device (CPU, GPU, TPU, ...).\n\n        Note:\n            This hook should only transfer the data and not modify it, nor should it move the data to\n            any other device than the one passed in as argument (unless you know what you are doing).\n\n        Note:\n            This hook only runs on single GPU training and DDP (no data-parallel).\n            Data-Parallel support will come in near future.\n\n        Args:\n            batch: A batch of data that needs to be transferred to a new device.\n            device: The target device as defined in PyTorch.\n\n        Returns:\n            A reference to the data on the new device.\n\n        Example::\n\n            def transfer_batch_to_device(self, batch, device):\n                if isinstance(batch, CustomBatch):\n                    # move all tensors in your custom data structure to the device\n                    batch.samples = batch.samples.to(device)\n                    batch.targets = batch.targets.to(device)\n                else:\n                    batch = super().transfer_batch_to_device(data, device)\n                return batch\n\n        Raises:\n            MisconfigurationException:\n                If using data-parallel, ``Trainer(accelerator=\'dp\')``.\n\n        See Also:\n            - :meth:`move_data_to_device`\n            - :meth:`apply_to_collection`\n        """\n        device = device or self.device\n        return move_data_to_device(batch, device)\n\n    def on_before_batch_transfer(self, batch, dataloader_idx):\n        """\n        Override to alter or apply batch augmentations to your batch before it is transferred to the device.\n\n        .. warning:: ``dataloader_idx`` always returns 0, and will be updated to support the true index in the future.\n\n        Note:\n            This hook only runs on single GPU training and DDP (no data-parallel).\n            Data-Parallel support will come in near future.\n\n        Args:\n            batch: A batch of data that needs to be altered or augmented.\n            dataloader_idx: DataLoader idx for batch\n\n        Returns:\n            A batch of data\n\n        Example::\n\n            def on_before_batch_transfer(self, batch, dataloader_idx):\n                batch[\'x\'] = transforms(batch[\'x\'])\n                return batch\n\n        Raises:\n            MisconfigurationException:\n                If using data-parallel, ``Trainer(accelerator=\'dp\')``.\n\n        See Also:\n            - :meth:`on_after_batch_transfer`\n            - :meth:`transfer_batch_to_device`\n        """\n        return batch\n\n    def on_after_batch_transfer(self, batch, dataloader_idx):\n        """\n        Override to alter or apply batch augmentations to your batch after it is transferred to the device.\n\n        .. warning:: ``dataloader_idx`` always returns 0, and will be updated to support the true ``idx`` in the future.\n\n        Note:\n            This hook only runs on single GPU training and DDP (no data-parallel).\n            Data-Parallel support will come in near future.\n\n        Args:\n            batch: A batch of data that needs to be altered or augmented.\n            dataloader_idx: DataLoader idx for batch (Default: 0)\n\n        Returns:\n            A batch of data\n\n        Example::\n\n            def on_after_batch_transfer(self, batch, dataloader_idx):\n                batch[\'x\'] = gpu_transforms(batch[\'x\'])\n                return batch\n\n        Raises:\n            MisconfigurationException:\n                If using data-parallel, ``Trainer(accelerator=\'dp\')``.\n\n        See Also:\n            - :meth:`on_before_batch_transfer`\n            - :meth:`transfer_batch_to_device`\n        """\n        return batch\n\n\nclass CheckpointHooks:\n    """Hooks to be used with Checkpointing."""\n\n    def on_load_checkpoint(self, checkpoint: Dict[str, Any]) -> None:\n        r"""\n        Called by Lightning to restore your model.\n        If you saved something with :meth:`on_save_checkpoint` this is your chance to restore this.\n\n        Args:\n            checkpoint: Loaded checkpoint\n\n        Example::\n\n            def on_load_checkpoint(self, checkpoint):\n                # 99% of the time you don\'t need to implement this method\n                self.something_cool_i_want_to_save = checkpoint[\'something_cool_i_want_to_save\']\n\n        Note:\n            Lightning auto-restores global step, epoch, and train state including amp scaling.\n            There is no need for you to restore anything regarding training.\n        """\n\n    def on_save_checkpoint(self, checkpoint: Dict[str, Any]) -> None:\n        r"""\n        Called by Lightning when saving a checkpoint to give you a chance to store anything\n        else you might want to save.\n\n        Args:\n            checkpoint: Checkpoint to be saved\n\n        Example::\n\n            def on_save_checkpoint(self, checkpoint):\n                # 99% of use cases you don\'t need to implement this method\n                checkpoint[\'something_cool_i_want_to_save\'] = my_cool_pickable_object\n\n        Note:\n            Lightning saves all aspects of training (epoch, global step, etc...)\n            including amp scaling.\n            There is no need for you to store anything about training.\n\n        """\n',
            'pytorch_lightning/trainer/predict_loop.py': '# Copyright The PyTorch Lightning team.\n#\n# Licensed under the Apache License, Version 2.0 (the "License");\n# you may not use this file except in compliance with the License.\n# You may obtain a copy of the License at\n#\n#     http://www.apache.org/licenses/LICENSE-2.0\n#\n# Unless required by applicable law or agreed to in writing, software\n# distributed under the License is distributed on an "AS IS" BASIS,\n# WITHOUT WARRANTIES OR CONDITIONS OF ANY KIND, either express or implied.\n# See the License for the specific language governing permissions and\n# limitations under the License.\nimport torch\n\nfrom pytorch_lightning.utilities.apply_func import apply_to_collection\nfrom pytorch_lightning.utilities.warnings import WarningCache\n\n\nclass PredictLoop(object):\n\n    def __init__(self, trainer):\n        self.trainer = trainer\n        self.max_batches = None\n        self.num_dataloaders = None\n        self.warning_cache = WarningCache()\n\n    def on_trainer_init(self):\n        self.trainer.num_predict_batches = []\n\n    def get_predict_dataloaders(self):\n        self.trainer.reset_predict_dataloader(self.trainer.lightning_module)\n\n        dataloaders = self.trainer.predict_dataloaders\n        max_batches = self.trainer.num_predict_batches\n\n        return dataloaders, max_batches\n\n    def should_skip_predict(self, max_batches):\n        return sum(max_batches) == 0\n\n    def on_predict_model_eval(self, *_, **__):\n        model_ref = self.trainer.lightning_module\n        model_ref.on_predict_model_eval()\n\n    def setup(self, model, max_batches, dataloaders):\n        self.trainer.call_hook("on_predict_start")\n\n        # copy properties for forward overrides\n        self.trainer.model_connector.copy_trainer_model_properties(model)\n\n        # convert max_batches to list\n        if isinstance(max_batches, int):\n            max_batches = [max_batches] * len(dataloaders)\n\n        self.max_batches = max_batches\n        self.num_dataloaders = self._get_num_dataloaders(dataloaders)\n        self._predictions = [[] for _ in range(self.num_dataloaders)]\n\n        self.trainer._progress_bar_callback.on_predict_start(self.trainer, self.trainer.lightning_module)\n\n    def _get_num_dataloaders(self, dataloaders):\n        # case where user does:\n        # return dl1, dl2\n        length = len(dataloaders)\n        if len(dataloaders) > 0 and isinstance(dataloaders[0], (list, tuple)):\n            length = len(dataloaders[0])\n        return length\n\n    def predict_step(self, batch, batch_idx, dataloader_idx):\n        # configure args\n        args = [batch, batch_idx]\n        if self.num_dataloaders:\n            args.append(dataloader_idx)\n\n        model_ref = self.trainer.lightning_module\n\n        model_ref._current_fx_name = "predict"\n        predictions = self.trainer.accelerator.predict_step(args)\n\n        if predictions is None:\n            self.warning_cache.warn("predict returned None if it was on purpose, ignore this warning...")\n\n        self._predictions[dataloader_idx].append(predictions)\n        self.trainer._progress_bar_callback.on_predict_batch_end(\n            self.trainer, model_ref, predictions, batch, batch_idx, dataloader_idx\n        )\n        return\n\n    def on_predict_epoch_end(self):\n        self.trainer.profiler.describe()\n\n        self.trainer._progress_bar_callback.on_predict_end(self.trainer, self.trainer.lightning_module)\n\n        results = self._predictions\n\n        def _convert_to_numpy(v):\n            return v.cpu().numpy()\n\n        results = apply_to_collection(results, torch.Tensor, _convert_to_numpy)\n\n        if len(results) == 1:\n            return results[0]\n\n        return results\n\n    def on_predict_start(self):\n        # hook\n        self.trainer.call_hook("on_predict_start")\n\n    def on_predict_end(self):\n        # hook\n        self.trainer.call_hook("on_predict_end")\n',
            'pytorch_lightning/trainer/trainer.py': '# Copyright The PyTorch Lightning team.\n#\n# Licensed under the Apache License, Version 2.0 (the "License");\n# you may not use this file except in compliance with the License.\n# You may obtain a copy of the License at\n#\n#     http://www.apache.org/licenses/LICENSE-2.0\n#\n# Unless required by applicable law or agreed to in writing, software\n# distributed under the License is distributed on an "AS IS" BASIS,\n# WITHOUT WARRANTIES OR CONDITIONS OF ANY KIND, either express or implied.\n# See the License for the specific language governing permissions and\n# limitations under the License.\n"""Trainer to automate the training."""\nimport logging\nimport warnings\nfrom itertools import count\nfrom pathlib import Path\nfrom traceback import print_exc\nfrom typing import Any, Dict, Iterable, List, Optional, Union\n\nimport torch\nfrom torch.utils.data import DataLoader\n\nfrom pytorch_lightning.accelerators import Accelerator\nfrom pytorch_lightning.callbacks import Callback\nfrom pytorch_lightning.core.datamodule import LightningDataModule\nfrom pytorch_lightning.core.lightning import LightningModule\nfrom pytorch_lightning.core.memory import ModelSummary\nfrom pytorch_lightning.core.step_result import Result\nfrom pytorch_lightning.loggers import LightningLoggerBase\nfrom pytorch_lightning.plugins import Plugin\nfrom pytorch_lightning.profiler import BaseProfiler\nfrom pytorch_lightning.trainer.callback_hook import TrainerCallbackHookMixin\nfrom pytorch_lightning.trainer.configuration_validator import ConfigValidator\nfrom pytorch_lightning.trainer.connectors.accelerator_connector import AcceleratorConnector\nfrom pytorch_lightning.trainer.connectors.callback_connector import CallbackConnector\nfrom pytorch_lightning.trainer.connectors.checkpoint_connector import CheckpointConnector\nfrom pytorch_lightning.trainer.connectors.data_connector import DataConnector\nfrom pytorch_lightning.trainer.connectors.debugging_connector import DebuggingConnector\nfrom pytorch_lightning.trainer.connectors.env_vars_connector import _defaults_from_env_vars\nfrom pytorch_lightning.trainer.connectors.logger_connector import LoggerConnector\nfrom pytorch_lightning.trainer.connectors.model_connector import ModelConnector\nfrom pytorch_lightning.trainer.connectors.optimizer_connector import OptimizerConnector\nfrom pytorch_lightning.trainer.connectors.profiler_connector import ProfilerConnector\nfrom pytorch_lightning.trainer.connectors.slurm_connector import SLURMConnector\nfrom pytorch_lightning.trainer.connectors.training_trick_connector import TrainingTricksConnector\nfrom pytorch_lightning.trainer.data_loading import TrainerDataLoadingMixin\nfrom pytorch_lightning.trainer.deprecated_api import DeprecatedDistDeviceAttributes, DeprecatedTrainerAttributes\nfrom pytorch_lightning.trainer.evaluation_loop import EvaluationLoop\nfrom pytorch_lightning.trainer.logging import TrainerLoggingMixin\nfrom pytorch_lightning.trainer.model_hooks import TrainerModelHooksMixin\nfrom pytorch_lightning.trainer.optimizers import TrainerOptimizersMixin\nfrom pytorch_lightning.trainer.predict_loop import PredictLoop\nfrom pytorch_lightning.trainer.properties import TrainerProperties\nfrom pytorch_lightning.trainer.states import TrainerState\nfrom pytorch_lightning.trainer.training_loop import TrainLoop\nfrom pytorch_lightning.trainer.training_tricks import TrainerTrainingTricksMixin\nfrom pytorch_lightning.tuner.tuning import Tuner\nfrom pytorch_lightning.utilities import DeviceType, rank_zero_warn\nfrom pytorch_lightning.utilities.debugging import InternalDebugger\nfrom pytorch_lightning.utilities.exceptions import MisconfigurationException\nfrom pytorch_lightning.utilities.memory import recursive_detach\nfrom pytorch_lightning.utilities.model_helpers import is_overridden\n\nlog = logging.getLogger(__name__)\n# warnings to ignore in trainer\nwarnings.filterwarnings(\n    \'ignore\', message=\'torch.distributed.reduce_op is deprecated, \'\n    \'please use torch.distributed.ReduceOp instead\'\n)\n\n\nclass Trainer(\n    TrainerProperties,\n    TrainerCallbackHookMixin,\n    TrainerModelHooksMixin,\n    TrainerOptimizersMixin,\n    TrainerLoggingMixin,\n    TrainerTrainingTricksMixin,\n    TrainerDataLoadingMixin,\n    DeprecatedDistDeviceAttributes,\n    DeprecatedTrainerAttributes,\n):\n\n    @_defaults_from_env_vars\n    def __init__(\n        self,\n        logger: Union[LightningLoggerBase, Iterable[LightningLoggerBase], bool] = True,\n        checkpoint_callback: bool = True,\n        callbacks: Optional[Union[List[Callback], Callback]] = None,\n        default_root_dir: Optional[str] = None,\n        gradient_clip_val: float = 0,\n        gradient_clip_algorithm: str = \'norm\',\n        process_position: int = 0,\n        num_nodes: int = 1,\n        num_processes: int = 1,\n        gpus: Optional[Union[List[int], str, int]] = None,\n        auto_select_gpus: bool = False,\n        tpu_cores: Optional[Union[List[int], str, int]] = None,\n        log_gpu_memory: Optional[str] = None,\n        progress_bar_refresh_rate: Optional[int] = None,\n        overfit_batches: Union[int, float] = 0.0,\n        track_grad_norm: Union[int, float, str] = -1,\n        check_val_every_n_epoch: int = 1,\n        fast_dev_run: Union[int, bool] = False,\n        accumulate_grad_batches: Union[int, Dict[int, int], List[list]] = 1,\n        max_epochs: Optional[int] = None,\n        min_epochs: Optional[int] = None,\n        max_steps: Optional[int] = None,\n        min_steps: Optional[int] = None,\n        limit_train_batches: Union[int, float] = 1.0,\n        limit_val_batches: Union[int, float] = 1.0,\n        limit_test_batches: Union[int, float] = 1.0,\n        limit_predict_batches: Union[int, float] = 1.0,\n        val_check_interval: Union[int, float] = 1.0,\n        flush_logs_every_n_steps: int = 100,\n        log_every_n_steps: int = 50,\n        accelerator: Optional[Union[str, Accelerator]] = None,\n        sync_batchnorm: bool = False,\n        precision: int = 32,\n        weights_summary: Optional[str] = \'top\',\n        weights_save_path: Optional[str] = None,\n        num_sanity_val_steps: int = 2,\n        truncated_bptt_steps: Optional[int] = None,\n        resume_from_checkpoint: Optional[Union[Path, str]] = None,\n        profiler: Optional[Union[BaseProfiler, str]] = None,\n        benchmark: bool = False,\n        deterministic: bool = False,\n        reload_dataloaders_every_epoch: bool = False,\n        auto_lr_find: Union[bool, str] = False,\n        replace_sampler_ddp: bool = True,\n        terminate_on_nan: bool = False,\n        auto_scale_batch_size: Union[str, bool] = False,\n        prepare_data_per_node: bool = True,\n        plugins: Optional[Union[Plugin, str, list]] = None,\n        amp_backend: str = \'native\',\n        amp_level: str = \'O2\',\n        distributed_backend: Optional[str] = None,\n        move_metrics_to_cpu: bool = False,\n        multiple_trainloader_mode: str = \'max_size_cycle\',\n        stochastic_weight_avg: bool = False\n    ):\n        r"""\n        Customize every aspect of training via flags\n\n        Args:\n\n            accelerator: Previously known as distributed_backend (dp, ddp, ddp2, etc...).\n                Can also take in an accelerator object for custom hardware.\n\n            accumulate_grad_batches: Accumulates grads every k batches or as set up in the dict.\n\n            amp_backend: The mixed precision backend to use ("native" or "apex")\n\n            amp_level: The optimization level to use (O1, O2, etc...).\n\n            auto_lr_find: If set to True, will make trainer.tune() run a learning rate finder,\n                trying to optimize initial learning for faster convergence. trainer.tune() method will\n                set the suggested learning rate in self.lr or self.learning_rate in the LightningModule.\n                To use a different key set a string instead of True with the key name.\n\n            auto_scale_batch_size: If set to True, will `initially` run a batch size\n                finder trying to find the largest batch size that fits into memory.\n                The result will be stored in self.batch_size in the LightningModule.\n                Additionally, can be set to either `power` that estimates the batch size through\n                a power search or `binsearch` that estimates the batch size through a binary search.\n\n            auto_select_gpus: If enabled and `gpus` is an integer, pick available\n                gpus automatically. This is especially useful when\n                GPUs are configured to be in "exclusive mode", such\n                that only one process at a time can access them.\n\n            benchmark: If true enables cudnn.benchmark.\n\n            callbacks: Add a callback or list of callbacks.\n\n            checkpoint_callback: If ``True``, enable checkpointing.\n                It will configure a default ModelCheckpoint callback if there is no user-defined ModelCheckpoint in\n                :paramref:`~pytorch_lightning.trainer.trainer.Trainer.callbacks`.\n\n            check_val_every_n_epoch: Check val every n train epochs.\n\n            default_root_dir: Default path for logs and weights when no logger/ckpt_callback passed.\n                Default: ``os.getcwd()``.\n                Can be remote file paths such as `s3://mybucket/path` or \'hdfs://path/\'\n\n            deterministic: If true enables cudnn.deterministic.\n\n            distributed_backend: deprecated. Please use \'accelerator\'\n\n            fast_dev_run: runs n if set to ``n`` (int) else 1 if set to ``True`` batch(es)\n                of train, val and test to find any bugs (ie: a sort of unit test).\n\n            flush_logs_every_n_steps: How often to flush logs to disk (defaults to every 100 steps).\n\n            gpus: number of gpus to train on (int) or which GPUs to train on (list or str) applied per node\n\n            gradient_clip_val: 0 means don\'t clip.\n\n            gradient_clip_algorithm: \'value\' means clip_by_value, \'norm\' means clip_by_norm. Default: \'norm\'\n\n            limit_train_batches: How much of training dataset to check (float = fraction, int = num_batches)\n\n            limit_val_batches: How much of validation dataset to check (float = fraction, int = num_batches)\n\n            limit_test_batches: How much of test dataset to check (float = fraction, int = num_batches)\n\n            limit_predict_batches: How much of prediction dataset to check (float = fraction, int = num_batches)\n\n            logger: Logger (or iterable collection of loggers) for experiment tracking.\n\n            log_gpu_memory: None, \'min_max\', \'all\'. Might slow performance\n\n            log_every_n_steps: How often to log within steps (defaults to every 50 steps).\n\n            prepare_data_per_node: If True, each LOCAL_RANK=0 will call prepare data.\n                Otherwise only NODE_RANK=0, LOCAL_RANK=0 will prepare data\n\n            process_position: orders the progress bar when running multiple models on same machine.\n\n            progress_bar_refresh_rate: How often to refresh progress bar (in steps). Value ``0`` disables progress bar.\n                Ignored when a custom progress bar is passed to :paramref:`~Trainer.callbacks`. Default: None, means\n                a suitable value will be chosen based on the environment (terminal, Google COLAB, etc.).\n\n            profiler: To profile individual steps during training and assist in identifying bottlenecks.\n\n            overfit_batches: Overfit a fraction of training data (float) or a set number of batches (int).\n\n            plugins: Plugins allow modification of core behavior like ddp and amp, and enable custom lightning plugins.\n\n            precision: Double precision (64), full precision (32) or half precision (16). Can be used on CPU, GPU or\n                TPUs.\n\n            max_epochs: Stop training once this number of epochs is reached. Disabled by default (None).\n                If both max_epochs and max_steps are not specified, defaults to ``max_epochs`` = 1000.\n\n            min_epochs: Force training for at least these many epochs. Disabled by default (None).\n                If both min_epochs and min_steps are not specified, defaults to ``min_epochs`` = 1.\n\n            max_steps: Stop training after this number of steps. Disabled by default (None).\n\n            min_steps: Force training for at least these number of steps. Disabled by default (None).\n\n            num_nodes: number of GPU nodes for distributed training.\n\n            num_processes: number of processes for distributed training with distributed_backend="ddp_cpu"\n\n            num_sanity_val_steps: Sanity check runs n validation batches before starting the training routine.\n                Set it to `-1` to run all batches in all validation dataloaders.\n\n            reload_dataloaders_every_epoch: Set to True to reload dataloaders every epoch.\n\n            replace_sampler_ddp: Explicitly enables or disables sampler replacement. If not specified this\n                will toggled automatically when DDP is used. By default it will add ``shuffle=True`` for\n                train sampler and ``shuffle=False`` for val/test sampler. If you want to customize it,\n                you can set ``replace_sampler_ddp=False`` and add your own distributed sampler.\n\n            resume_from_checkpoint: Path/URL of the checkpoint from which training is resumed. If there is\n                no checkpoint file at the path, start from scratch. If resuming from mid-epoch checkpoint,\n                training will start from the beginning of the next epoch.\n\n            sync_batchnorm: Synchronize batch norm layers between process groups/whole world.\n\n            terminate_on_nan: If set to True, will terminate training (by raising a `ValueError`) at the\n                end of each training batch, if any of the parameters or the loss are NaN or +/-inf.\n\n            tpu_cores: How many TPU cores to train on (1 or 8) / Single TPU to train on [1]\n\n            track_grad_norm: -1 no tracking. Otherwise tracks that p-norm. May be set to \'inf\' infinity-norm.\n\n            truncated_bptt_steps: Truncated back prop breaks performs backprop every k steps of much longer\n                sequence.\n\n            val_check_interval: How often to check the validation set. Use float to check within a training epoch,\n                use int to check every n steps (batches).\n\n            weights_summary: Prints a summary of the weights when training begins.\n\n            weights_save_path: Where to save weights if specified. Will override default_root_dir\n                for checkpoints only. Use this if for whatever reason you need the checkpoints\n                stored in a different place than the logs written in `default_root_dir`.\n                Can be remote file paths such as `s3://mybucket/path` or \'hdfs://path/\'\n                Defaults to `default_root_dir`.\n\n            move_metrics_to_cpu: Whether to force internal logged metrics to be moved to cpu.\n                This can save some gpu memory, but can make training slower. Use with attention.\n\n            multiple_trainloader_mode: How to loop over the datasets when there are multiple train loaders.\n                In \'max_size_cycle\' mode, the trainer ends one epoch when the largest dataset is traversed,\n                and smaller datasets reload when running out of their data. In \'min_size\' mode, all the datasets\n                reload when reaching the minimum length of datasets.\n\n            stochastic_weight_avg: Whether to use `Stochastic Weight Averaging (SWA)\n                <https://pytorch.org/blog/pytorch-1.6-now-includes-stochastic-weight-averaging/>_`\n\n        """\n        super().__init__()\n\n        distributed_backend = distributed_backend or accelerator\n\n        # init connectors\n        self.dev_debugger = InternalDebugger(self)\n        self.config_validator = ConfigValidator(self)\n        self.data_connector = DataConnector(self)\n        self.optimizer_connector = OptimizerConnector(self)\n\n        self.accelerator_connector = AcceleratorConnector(\n            num_processes, tpu_cores, distributed_backend, auto_select_gpus, gpus, num_nodes, sync_batchnorm, benchmark,\n            replace_sampler_ddp, deterministic, precision, amp_backend, amp_level, plugins\n        )\n        self.logger_connector = LoggerConnector(self, log_gpu_memory)\n        self.model_connector = ModelConnector(self)\n        self.callback_connector = CallbackConnector(self)\n        self.debugging_connector = DebuggingConnector(self)\n        self.training_tricks_connector = TrainingTricksConnector(self)\n        self.profile_connector = ProfilerConnector(self)\n        self.checkpoint_connector = CheckpointConnector(self)\n        self.slurm_connector = SLURMConnector(self)\n        self.tuner = Tuner(self)\n        self.train_loop = TrainLoop(self, multiple_trainloader_mode)\n        self.evaluation_loop = EvaluationLoop(self)\n        self.predict_loop = PredictLoop(self)\n\n        # training state\n        if weights_summary is not None and weights_summary not in ModelSummary.MODES:\n            raise MisconfigurationException(\n                f"`weights_summary` can be None, {\', \'.join(ModelSummary.MODES)}, but got {weights_summary}"\n            )\n        self.weights_summary = weights_summary\n        self.shown_warnings = set()\n\n        # init callbacks\n        # Declare attributes to be set in callback_connector on_trainer_init\n        self.callback_connector.on_trainer_init(\n            callbacks, checkpoint_callback, progress_bar_refresh_rate, process_position, default_root_dir,\n            weights_save_path, resume_from_checkpoint, stochastic_weight_avg\n        )\n\n        # hook\n        self.on_init_start()\n\n        # init optimizer + lr scheduler related flags\n        self.optimizer_connector.on_trainer_init()\n\n        # init data flags\n        self.data_connector.on_trainer_init(\n            check_val_every_n_epoch, reload_dataloaders_every_epoch, prepare_data_per_node\n        )\n\n        # init training tricks\n        self.training_tricks_connector.on_trainer_init(\n            gradient_clip_val,\n            gradient_clip_algorithm,\n            track_grad_norm,\n            accumulate_grad_batches,\n            truncated_bptt_steps,\n            terminate_on_nan,\n        )\n        self.train_loop.on_trainer_init(\n            max_epochs,\n            min_epochs,\n            max_steps,\n            min_steps,\n            num_sanity_val_steps,\n        )\n        self.evaluation_loop.on_trainer_init()\n\n        # configure tuner\n        self.tuner.on_trainer_init(auto_lr_find, auto_scale_batch_size)\n\n        # configure profiler\n        self.profile_connector.on_trainer_init(profiler)\n\n        # init logger flags\n        self.logger_connector.on_trainer_init(\n            logger,\n            flush_logs_every_n_steps,\n            log_every_n_steps,\n            move_metrics_to_cpu,\n        )\n\n        # init debugging flags\n        self.debugging_connector.on_init_start(\n            limit_train_batches,\n            limit_val_batches,\n            limit_test_batches,\n            limit_predict_batches,\n            val_check_interval,\n            overfit_batches,\n            fast_dev_run,\n        )\n\n        # Callback system\n        self.on_init_end()\n\n    def fit(\n        self,\n        model: LightningModule,\n        train_dataloader: Any = None,\n        val_dataloaders: Optional[Union[DataLoader, List[DataLoader]]] = None,\n        datamodule: Optional[LightningDataModule] = None,\n    ):\n        r"""\n        Runs the full optimization routine.\n\n        Args:\n            datamodule: A instance of :class:`LightningDataModule`.\n\n            model: Model to fit.\n\n            train_dataloader: Either a single PyTorch DataLoader or a collection of these\n                (list, dict, nested lists and dicts). In the case of multiple dataloaders, please\n                see this :ref:`page <multiple-training-dataloaders>`\n\n            val_dataloaders: Either a single Pytorch Dataloader or a list of them, specifying validation samples.\n                If the model has a predefined val_dataloaders method this will be skipped\n\n        """\n        # we reuse fit for other functions. When already set, it shouldn\'t be modified.\n        if not self.state.running:\n            self.state = TrainerState.FITTING\n        if self._running_stage is None:\n            self.training = True\n\n        # set local properties on the model\n        self.model_connector.copy_trainer_model_properties(model)\n\n        # ----------------------------\n        # LINK DATA\n        # ----------------------------\n        # setup data, etc...\n        self.train_loop.setup_fit(model, train_dataloader, val_dataloaders, datamodule)\n\n        # hook\n        self.data_connector.prepare_data(model)\n        self.callback_connector._attach_model_callbacks(model, self)\n\n        # ----------------------------\n        # SET UP TRAINING\n        # ----------------------------\n        self.call_hook("on_before_accelerator_backend_setup", model)\n        self.accelerator.connect(model)\n        self.accelerator.setup_environment()\n        self.call_setup_hook(model)  # allow user to setup lightning_module in accelerator environment\n        self.call_configure_sharded_model(model)  # allow user to setup in model sharded environment\n        self.accelerator.setup(self, model)  # note: this sets up self.lightning_module\n\n        # ----------------------------\n        # INSPECT THE CORE LOOPS\n        # ----------------------------\n        f"""\n             Lightning internal flow looks like this:\n        {Trainer.fit} or {Trainer.test} or {Trainer.predict}  ||\n                                |                             ||\n                        create accelerator                    ||\n                                |                             ||\n                         {self.dispatch}                      ||\n                                |                             ||  LIGHTNING\n                  {self.accelerator.start_training}           ||\n                or {self.accelerator.start_evaluating}        ||\n                or {self.accelerator.start_predicting}        ||  FLOW\n                                |                             ||\n                         {self.run_stage}                     ||\n                                |                             ||  DIRECTION\n                        {self.run_train}                      ||\n                     or {self.run_evaluation}                 ||\n                     or {self.run_predict}                    ||\n                                |                             ||\n                             results                          \\/\n        This is used to guide readers to the core loops: train, test, predict.\n        {self.run_predict} is the simplest to understand, use `Go to Definition` to read it :)\n        Search for `start_training` or `start_evaluating` or `start_predicting` in\n        `pytorch_lightning/plugins/training_type_plugin` to find accelerator dispatch functions.\n        """  # noqa: W605\n\n        # ----------------------------\n        # TRAIN\n        # ----------------------------\n        # hook\n        if self.state == TrainerState.FITTING:\n            self.call_hook("on_fit_start")\n\n        # plugin will setup fitting (e.g. ddp will launch child processes)\n        self.pre_dispatch()\n\n        # dispatch `start_training` or `start_evaluating` or `start_predicting`\n        self.dispatch()\n\n        # plugin will finalized fitting (e.g. ddp_spawn will load trained model)\n        self.post_dispatch()\n\n        # ----------------------------\n        # POST-Training CLEAN UP\n        # ----------------------------\n        # hook\n        if self.state == TrainerState.FITTING:\n            self.call_hook(\'on_fit_end\')\n\n        # teardown\n        self.call_teardown_hook(model)\n\n        if self.state != TrainerState.INTERRUPTED:\n            self.state = TrainerState.FINISHED\n        self._running_stage = None\n\n        # return 1 when finished\n        # used for testing or when we need to know that training succeeded\n        return self.accelerator.results or 1\n\n    def pre_dispatch(self):\n        self.accelerator.pre_dispatch(self)\n\n        # log hyper-parameters\n        if self.logger is not None:\n            # save exp to get started (this is where the first experiment logs are written)\n            self.logger.log_hyperparams(self.lightning_module.hparams_initial)\n            self.logger.log_graph(self.lightning_module)\n            self.logger.save()\n\n    def post_dispatch(self):\n        self.accelerator.post_dispatch(self)\n        self.accelerator.teardown()\n\n    def dispatch(self):\n        if self.evaluating:\n            self.accelerator.start_evaluating(self)\n        elif self.predicting:\n            self.accelerator.start_predicting(self)\n        else:\n            self.accelerator.start_training(self)\n\n    def run_stage(self):\n        results = None\n\n        self.profile_connector.setup()\n\n        if self.evaluating:\n            results = self.run_evaluate()\n        elif self.predicting:\n            results = self.run_predict()\n        else:\n            self.run_train()\n        return results\n\n    def _pre_training_routine(self):\n        # wait for all to join if on distributed\n        self.accelerator.barrier("setup_training")\n\n        # register auto-resubmit when on SLURM\n        self.slurm_connector.register_slurm_signal_handlers()\n\n        # --------------------------\n        # Pre-train\n        # --------------------------\n        # on pretrain routine start\n        ref_model = self.lightning_module\n\n        self.on_pretrain_routine_start()\n        ref_model.on_pretrain_routine_start()\n\n        # print model summary\n        if self.is_global_zero and self.weights_summary is not None and not self.testing:\n            ref_model.summarize(mode=self.weights_summary)\n\n        # restore training and model before hpc is called\n        self.checkpoint_connector.restore_weights()\n\n        # on pretrain routine end\n        self.on_pretrain_routine_end()\n        ref_model.on_pretrain_routine_end()\n\n    def run_train(self) -> None:\n\n        self._pre_training_routine()\n\n        if not self.is_global_zero and self.progress_bar_callback is not None:\n            self.progress_bar_callback.disable()\n\n        self.run_sanity_check(self.lightning_module)\n\n        self.checkpoint_connector.has_trained = False\n\n        # enable train mode\n        model = self.lightning_module\n        model.train()\n        torch.set_grad_enabled(True)\n\n        # reload data when needed\n        self.train_loop.reset_train_val_dataloaders(model)\n\n        # hook\n        self.train_loop.on_train_start()\n\n        try:\n            if self.train_loop.should_skip_training():\n                return\n            # run all epochs\n            epochs = range(self.current_epoch, self.max_epochs) if self.max_epochs else count(self.current_epoch)\n            for epoch in epochs:\n\n                # hook\n                self.train_loop.on_train_epoch_start(epoch)\n\n                with self.profiler.profile("run_training_epoch"):\n                    # run train epoch\n                    self.train_loop.run_training_epoch()\n\n                if self.max_steps and self.max_steps <= self.global_step:\n                    return\n\n                # early stopping\n                met_min_epochs = (epoch >= self.min_epochs - 1) if self.min_epochs else True\n                met_min_steps = self.global_step >= self.min_steps if self.min_steps else True\n\n                if self.should_stop:\n                    if met_min_epochs and met_min_steps:\n                        return\n                    else:\n                        log.info(\n                            \'Trainer was signaled to stop but required minimum epochs\'\n                            f\' ({self.min_epochs}) or minimum steps ({self.min_steps}) has\'\n                            \' not been met. Training will continue...\'\n                        )\n                        self.should_stop = False\n\n            # hook\n            self.train_loop.on_train_end()\n\n        except KeyboardInterrupt:\n            rank_zero_warn(\'Detected KeyboardInterrupt, attempting graceful shutdown...\')\n            # user could press Ctrl+c many times... only shutdown once\n            if not self.interrupted:\n                self.state = TrainerState.INTERRUPTED\n                self.on_keyboard_interrupt()\n        except (RuntimeError, AssertionError):\n            # if an exception is raised, the finally block is executed and can hide the actual exception\n            # that was initially raised if `on_train_end` also raises an exception. we want to avoid that\n            # for assertions and other runtime errors so we aren\'t misled while debugging\n            print_exc()\n        finally:\n            # hook\n            self.train_loop.on_train_end()\n\n    def run_evaluation(self, on_epoch=False):\n        if not (self.evaluating or self.sanity_checking):\n            rank_zero_warn(\n                f"`trainer.run_evaluation()` was called but the running stage is set to {self._running_stage}."\n                " This should not happen normally. Setting it to `RunningStage.VALIDATING`", RuntimeWarning\n            )\n            self.validating = True\n\n        # reset cached results\n        self.logger_connector.reset()\n\n        # prepare dataloaders\n        dataloaders, max_batches = self.evaluation_loop.get_evaluation_dataloaders()\n\n        # check if we want to skip this evaluation\n        if self.evaluation_loop.should_skip_evaluation(max_batches):\n            return [], []\n\n        # enable eval mode + no grads\n        self.evaluation_loop.on_evaluation_model_eval()\n        # ref model\n        model = self.lightning_module\n        model.zero_grad()\n        torch.set_grad_enabled(False)\n\n        # hook\n        self.evaluation_loop.on_evaluation_start()\n\n        # set up the eval loop\n        self.evaluation_loop.setup(model, max_batches, dataloaders)\n\n        # hook\n        self.evaluation_loop.on_evaluation_epoch_start()\n\n        # run validation/testing\n        for dataloader_idx, dataloader in enumerate(dataloaders):\n            # bookkeeping\n            dl_outputs = []\n            dataloader = self.accelerator.process_dataloader(dataloader)\n            dl_max_batches = self.evaluation_loop.max_batches[dataloader_idx]\n\n            for batch_idx, batch in enumerate(dataloader):\n                if batch is None:\n                    continue\n\n                # stop short when running on limited batches\n                if batch_idx >= dl_max_batches:\n                    break\n\n                # hook\n                self.evaluation_loop.on_evaluation_batch_start(batch, batch_idx, dataloader_idx)\n\n                # lightning module methods\n                with self.profiler.profile("evaluation_step_and_end"):\n                    output = self.evaluation_loop.evaluation_step(batch, batch_idx, dataloader_idx)\n                    output = self.evaluation_loop.evaluation_step_end(output)\n\n                # hook + store predictions\n                self.evaluation_loop.on_evaluation_batch_end(output, batch, batch_idx, dataloader_idx)\n\n                # log batch metrics\n                self.evaluation_loop.log_evaluation_step_metrics(output, batch_idx)\n\n                # track epoch level outputs\n                dl_outputs = self.track_output_for_epoch_end(dl_outputs, output)\n\n            # store batch level output per dataloader\n            self.evaluation_loop.outputs.append(dl_outputs)\n\n        # lightning module method\n        deprecated_eval_results = self.evaluation_loop.evaluation_epoch_end()\n\n        # hook\n        self.evaluation_loop.on_evaluation_epoch_end()\n\n        # update epoch-level lr_schedulers\n        if on_epoch:\n            self.optimizer_connector.update_learning_rates(interval=\'epoch\')\n\n        # hook\n        self.evaluation_loop.on_evaluation_end()\n\n        # log epoch metrics\n        eval_loop_results = self.evaluation_loop.log_epoch_metrics_on_evaluation_end()\n\n        # save predictions to disk\n        self.evaluation_loop.predictions.to_disk()\n\n        # enable train mode again\n        self.evaluation_loop.on_evaluation_model_train()\n\n        torch.set_grad_enabled(True)\n\n        return eval_loop_results, deprecated_eval_results\n\n    def track_output_for_epoch_end(self, outputs, output):\n        if output is not None:\n            if isinstance(output, Result):\n                output = output.detach()\n                if self.move_metrics_to_cpu:\n                    output = output.cpu()\n            elif isinstance(output, dict):\n                output = recursive_detach(output, to_cpu=self.move_metrics_to_cpu)\n            elif isinstance(output, torch.Tensor) and output.is_cuda and self.move_metrics_to_cpu:\n                output = output.cpu()\n            outputs.append(output)\n        return outputs\n\n    def run_evaluate(self):\n        if not self.is_global_zero and self.progress_bar_callback is not None:\n            self.progress_bar_callback.disable()\n\n        assert self.evaluating\n\n        with self.profiler.profile(f"run_{self._running_stage}_evaluation"):\n            eval_loop_results, _ = self.run_evaluation()\n\n        if len(eval_loop_results) == 0:\n            return 1\n\n        # remove the tensors from the eval results\n        for i, result in enumerate(eval_loop_results):\n            if isinstance(result, dict):\n                for k, v in result.items():\n                    if isinstance(v, torch.Tensor):\n                        result[k] = v.cpu().item()\n\n        return eval_loop_results\n\n    def run_predict(self):\n        self.predict_loop.on_predict_start()\n\n        # prepare dataloaders\n        dataloaders, max_batches = self.predict_loop.get_predict_dataloaders()\n\n        # check if we want to skip this evaluation\n        if self.predict_loop.should_skip_predict(max_batches):\n            return []\n\n        # ref model\n        model = self.lightning_module\n\n        # enable eval mode + no grads\n        self.predict_loop.on_predict_model_eval()\n        model.zero_grad()\n        torch.set_grad_enabled(False)\n\n        # set up the eval loop\n        self.predict_loop.setup(model, max_batches, dataloaders)\n\n        # run validation/testing\n        for dataloader_idx, dataloader in enumerate(dataloaders):\n            dataloader = self.accelerator.process_dataloader(dataloader)\n            dl_max_batches = self.predict_loop.max_batches[dataloader_idx]\n            for batch_idx, batch in enumerate(dataloader):\n                if batch is None:\n                    continue\n\n                # stop short when running on limited batches\n                if batch_idx >= dl_max_batches:\n                    break\n\n                # lightning module methods\n                with self.profiler.profile("predict_step"):\n                    self.predict_loop.predict_step(batch, batch_idx, dataloader_idx)\n\n        results = self.predict_loop.on_predict_epoch_end()\n        self.predict_loop.on_predict_end()\n\n        # re-enable grads\n        torch.set_grad_enabled(True)\n\n        return results\n\n    def run_sanity_check(self, ref_model):\n        using_val_step = ref_model.val_dataloader is not None and is_overridden(\'validation_step\', ref_model)\n        should_sanity_check = using_val_step and self.num_sanity_val_steps > 0 and self.limit_val_batches > 0\n\n        # run tiny validation (if validation defined)\n        # to make sure program won\'t crash during val\n        if should_sanity_check:\n            stage = self._running_stage\n            self.sanity_checking = True\n\n            # hook and callback\n            self.on_sanity_check_start()\n\n            # run eval step\n            _, eval_results = self.run_evaluation()\n\n            self.on_sanity_check_end()\n\n            self._running_stage = stage\n\n    def validate(\n        self,\n        model: Optional[LightningModule] = None,\n        val_dataloaders: Optional[Union[DataLoader, List[DataLoader]]] = None,\n        ckpt_path: Optional[str] = \'best\',\n        verbose: bool = True,\n        datamodule: Optional[LightningDataModule] = None,\n    ):\n        r"""\n        Perform one evaluation epoch over the validation set.\n\n        Args:\n            model: The model to validate.\n\n            val_dataloaders: Either a single PyTorch DataLoader or a list of them,\n                specifying validation samples.\n\n            ckpt_path: Either ``best`` or path to the checkpoint you wish to validate.\n                If ``None``, use the current weights of the model.\n                When the model is given as argument, this parameter will not apply.\n\n            verbose: If True, prints the validation results.\n\n            datamodule: A instance of :class:`LightningDataModule`.\n\n        Returns:\n            The dictionary with final validation results returned by validation_epoch_end.\n            If validation_epoch_end is not defined, the output is a list of the dictionaries\n            returned by validation_step.\n        """\n        # --------------------\n        # SETUP HOOK\n        # --------------------\n        self.verbose_evaluate = verbose\n\n        self.state = TrainerState.VALIDATING\n        self.validating = True\n\n        # If you supply a datamodule you can\'t supply val_dataloaders\n        if val_dataloaders is not None and datamodule:\n            raise MisconfigurationException(\n                \'You cannot pass both `trainer.validate(val_dataloaders=..., datamodule=...)`\'\n            )\n\n        model_provided = model is not None\n        model = model or self.lightning_module\n\n        # Attach datamodule to get setup/prepare_data added to model before the call to it below\n        self.data_connector.attach_datamodule(model, datamodule)\n        #  Attach dataloaders (if given)\n        self.data_connector.attach_dataloaders(model, val_dataloaders=val_dataloaders)\n\n        if not model_provided:\n            self.validated_ckpt_path = self.__load_ckpt_weights(model, ckpt_path=ckpt_path)\n\n        # run validate\n        results = self.fit(model)\n\n        assert self.state.stopped\n        self.validating = False\n\n        return results\n\n    def test(\n        self,\n        model: Optional[LightningModule] = None,\n        test_dataloaders: Optional[Union[DataLoader, List[DataLoader]]] = None,\n        ckpt_path: Optional[str] = \'best\',\n        verbose: bool = True,\n        datamodule: Optional[LightningDataModule] = None,\n    ):\n        r"""\n        Perform one evaluation epoch over the test set. It\'s separated from\n        fit to make sure you never run on your test set until you want to.\n\n        Args:\n            model: The model to test.\n\n            test_dataloaders: Either a single PyTorch DataLoader or a list of them,\n                specifying test samples.\n\n            ckpt_path: Either ``best`` or path to the checkpoint you wish to test.\n                If ``None``, use the current weights of the model.\n                When the model is given as argument, this parameter will not apply.\n\n            verbose: If True, prints the test results.\n\n            datamodule: A instance of :class:`LightningDataModule`.\n\n        Returns:\n            Returns a list of dictionaries, one for each test dataloader containing their respective metrics.\n        """\n        # --------------------\n        # SETUP HOOK\n        # --------------------\n        self.verbose_evaluate = verbose\n\n        self.state = TrainerState.TESTING\n        self.testing = True\n\n        # If you supply a datamodule you can\'t supply test_dataloaders\n        if test_dataloaders is not None and datamodule:\n            raise MisconfigurationException(\'You cannot pass both `trainer.test(test_dataloaders=..., datamodule=...)`\')\n\n        model_provided = model is not None\n        model = model or self.lightning_module\n\n        # Attach datamodule to get setup/prepare_data added to model before the call to it below\n        self.data_connector.attach_datamodule(model, datamodule)\n        #  Attach dataloaders (if given)\n        self.data_connector.attach_dataloaders(model, test_dataloaders=test_dataloaders)\n\n        if not model_provided:\n            self.tested_ckpt_path = self.__load_ckpt_weights(model, ckpt_path=ckpt_path)\n\n        # run test\n        results = self.fit(model)\n\n        assert self.state.stopped\n        self.testing = False\n\n        return results\n\n    def __load_ckpt_weights(\n        self,\n        model,\n        ckpt_path: Optional[str] = None,\n    ) -> Optional[str]:\n        if ckpt_path is None:\n            return\n\n        fn = self.state.value\n\n        if ckpt_path == \'best\':\n            # if user requests the best checkpoint but we don\'t have it, error\n            if not self.checkpoint_callback.best_model_path:\n                if self.fast_dev_run:\n                    raise MisconfigurationException(\n                        f\'You cannot execute `.{fn}()` with `fast_dev_run=True` unless you do\'\n                        f\' `.{fn}(ckpt_path=PATH)` as no checkpoint path was generated during fitting.\'\n                    )\n                raise MisconfigurationException(\n                    f\'`.{fn}(ckpt_path="best")` is set but `ModelCheckpoint` is not configured to save the best model.\'\n                )\n            # load best weights\n            ckpt_path = self.checkpoint_callback.best_model_path\n\n        if not ckpt_path:\n            raise MisconfigurationException(\n                f\'`.{fn}()` found no path for the best weights: "{ckpt_path}". Please\'\n                f\' specify a path for a checkpoint `.{fn}(ckpt_path=PATH)`\'\n            )\n\n        # only one process running at this point for TPUs, as spawn isn\'t triggered yet\n        # todo: move this logic internally within the barrier.\n        if not self._device_type == DeviceType.TPU:\n            self.training_type_plugin.barrier()\n\n        self.training_type_plugin.restore_model_state_from_ckpt_path(\n            ckpt_path, map_location=lambda storage, loc: storage\n        )\n        return ckpt_path\n\n    def predict(\n        self,\n        model: Optional[LightningModule] = None,\n        dataloaders: Optional[Union[DataLoader, List[DataLoader]]] = None,\n        datamodule: Optional[LightningDataModule] = None,\n    ):\n        r"""\n\n        Separates from fit to make sure you never run on your predictions set until you want to.\n\n        This will call the model forward function to compute predictions.\n\n        Args:\n            model: The model to predict on.\n\n            dataloaders: Either a single\n                Pytorch Dataloader or a list of them, specifying inference samples.\n\n            datamodule: A instance of :class:`LightningDataModule`.\n\n        Returns:\n            Returns a list of dictionaries, one for each provided dataloader containing their respective predictions.\n        """\n\n        # --------------------\n        # SETUP HOOK\n        # --------------------\n        # If you supply a datamodule you can\'t supply dataloaders\n\n        model = model or self.lightning_module\n\n        self.state = TrainerState.PREDICTING\n        self.predicting = True\n\n        if dataloaders is not None and datamodule:\n            raise MisconfigurationException(\n                \'You cannot pass dataloaders to trainer.predict if you supply a datamodule.\'\n            )\n\n        # Attach datamodule to get setup/prepare_data added to model before the call to it below\n        self.data_connector.attach_datamodule(model, datamodule)\n        #  Attach dataloaders (if given)\n        self.data_connector.attach_dataloaders(model, predict_dataloaders=dataloaders)\n\n        results = self.fit(model)\n\n        assert self.state.stopped\n        self.predicting = False\n\n        return results\n\n    def tune(\n        self,\n        model: LightningModule,\n        train_dataloader: Optional[DataLoader] = None,\n        val_dataloaders: Optional[Union[DataLoader, List[DataLoader]]] = None,\n        datamodule: Optional[LightningDataModule] = None,\n    ):\n        r"""\n        Runs routines to tune hyperparameters before training.\n\n        Args:\n            datamodule: A instance of :class:`LightningDataModule`.\n\n            model: Model to tune.\n\n            train_dataloader: A Pytorch DataLoader with training samples. If the model has\n                a predefined train_dataloader method this will be skipped.\n\n            val_dataloaders: Either a single Pytorch Dataloader or a list of them, specifying validation samples.\n                If the model has a predefined val_dataloaders method this will be skipped\n\n        """\n        self.state = TrainerState.TUNING\n        self.tuning = True\n\n        self.tuner.tune(model, train_dataloader, val_dataloaders, datamodule)\n\n        assert self.state.stopped\n        self.tuning = False\n\n    def call_setup_hook(self, model: LightningModule) -> None:\n        assert self.state.running, f"TrainerState: {self.state}"\n        state = self._setup_state\n\n        if self.datamodule is not None:\n            called = getattr(self.datamodule, f\'has_setup_{state}\')\n            if not called:\n                self.datamodule.setup(stage=state)\n\n        self.setup(model, stage=state)\n        model.setup(stage=state)\n\n    def call_configure_sharded_model(self, model: LightningModule) -> None:\n        # Call configure sharded model hook if accelerator requests. In some cases\n        # we will not call the hook; the hook has initialized the sharded model for example.\n\n        # used on the model if the user re-create a trainer with resume_from_checkpoint\n        model_call_configure_sharded_model_hook = getattr(model, "call_configure_sharded_model_hook", False)\n        if self.accelerator.call_configure_sharded_model_hook and not model_call_configure_sharded_model_hook:\n            with self.accelerator.model_sharded_context():\n                model.configure_sharded_model()\n                self.configure_sharded_model(model)\n            model.call_configure_sharded_model_hook = True\n            self.accelerator.call_configure_sharded_model_hook = False\n\n    def call_teardown_hook(self, model: LightningModule) -> None:\n        state = self._teardown_state\n\n        if self.datamodule is not None:\n            called = getattr(self.datamodule, f\'has_teardown_{state}\')\n            if not called:\n                self.datamodule.teardown(stage=state)\n\n        self.profiler.teardown(stage=state)\n        self.teardown(stage=state)\n        model.teardown(stage=state)\n\n    def _reset_result_and_set_hook_fx_name(self, hook_name):\n        # on_before_zero_grad is called within training_step\n        if "batch_start" in hook_name or "on_before_zero_grad" in hook_name:\n            return True\n        model_ref = self.lightning_module\n        if model_ref is not None:\n            # used to track current hook name called\n            model_ref._results = Result()\n            model_ref._current_hook_fx_name = hook_name\n        return False\n\n    def _cache_logged_metrics(self):\n        model_ref = self.lightning_module\n        if model_ref is not None:\n            # capture logging for this hook\n            self.logger_connector.cache_logged_metrics()\n\n    def call_hook(self, hook_name, *args, **kwargs):\n        # set hook_name to model + reset Result obj\n        skip = self._reset_result_and_set_hook_fx_name(hook_name)\n\n        # always profile hooks\n        with self.profiler.profile(hook_name):\n\n            # first call trainer hook\n            if hasattr(self, hook_name):\n                trainer_hook = getattr(self, hook_name)\n                trainer_hook(*args, **kwargs)\n\n            # next call hook in lightningModule\n            output = None\n            model_ref = self.lightning_module\n            if is_overridden(hook_name, model_ref):\n                hook_fx = getattr(model_ref, hook_name)\n                output = hook_fx(*args, **kwargs)\n\n            # if the PL module doesn\'t have the hook then call the accelerator\n            # used to auto-reduce things for the user with Results obj\n            elif hasattr(self.accelerator, hook_name):\n                accelerator_hook = getattr(self.accelerator, hook_name)\n                output = accelerator_hook(*args, **kwargs)\n\n        if not skip:\n            self._cache_logged_metrics()\n        return output\n',
            'tests/trainer/test_trainer.py': '# Copyright The PyTorch Lightning team.\n#\n# Licensed under the Apache License, Version 2.0 (the "License");\n# you may not use this file except in compliance with the License.\n# You may obtain a copy of the License at\n#\n#     http://www.apache.org/licenses/LICENSE-2.0\n#\n# Unless required by applicable law or agreed to in writing, software\n# distributed under the License is distributed on an "AS IS" BASIS,\n# WITHOUT WARRANTIES OR CONDITIONS OF ANY KIND, either express or implied.\n# See the License for the specific language governing permissions and\n# limitations under the License.\nimport logging\nimport math\nimport os\nimport pickle\nimport sys\nfrom argparse import Namespace\nfrom copy import deepcopy\nfrom pathlib import Path\nfrom unittest.mock import ANY, call, patch\n\nimport cloudpickle\nimport pytest\nimport torch\nfrom omegaconf import OmegaConf\nfrom torch.optim import SGD\nfrom torch.utils.data import DataLoader\n\nimport tests.helpers.utils as tutils\nfrom pytorch_lightning import Callback, LightningDataModule, LightningModule, Trainer\nfrom pytorch_lightning.callbacks import EarlyStopping, ModelCheckpoint\nfrom pytorch_lightning.core.saving import load_hparams_from_tags_csv, load_hparams_from_yaml, save_hparams_to_tags_csv\nfrom pytorch_lightning.loggers import TensorBoardLogger\nfrom pytorch_lightning.profiler import AdvancedProfiler, PassThroughProfiler, PyTorchProfiler, SimpleProfiler\nfrom pytorch_lightning.trainer.states import TrainerState\nfrom pytorch_lightning.utilities.cloud_io import load as pl_load\nfrom pytorch_lightning.utilities.exceptions import MisconfigurationException\nfrom tests.base import EvalModelTemplate\nfrom tests.helpers import BoringModel, RandomDataset\nfrom tests.helpers.runif import RunIf\n\n\n@pytest.mark.parametrize("url_ckpt", [True, False])\ndef test_no_val_module(monkeypatch, tmpdir, tmpdir_server, url_ckpt):\n    """Tests use case where trainer saves the model, and user loads it from tags independently."""\n    # set $TORCH_HOME, which determines torch hub\'s cache path, to tmpdir\n    monkeypatch.setenv("TORCH_HOME", str(tmpdir))\n\n    model = EvalModelTemplate()\n\n    # logger file to get meta\n    logger = tutils.get_default_logger(tmpdir)\n\n    trainer = Trainer(\n        default_root_dir=tmpdir,\n        max_epochs=1,\n        logger=logger,\n        callbacks=[ModelCheckpoint(dirpath=tmpdir)],\n    )\n    # fit model\n    trainer.fit(model)\n    # training complete\n    assert trainer.state == TrainerState.FINISHED, f"Training failed with {trainer.state}"\n\n    # save model\n    new_weights_path = os.path.join(tmpdir, "save_test.ckpt")\n    trainer.save_checkpoint(new_weights_path)\n\n    # assert ckpt has hparams\n    ckpt = torch.load(new_weights_path)\n    assert LightningModule.CHECKPOINT_HYPER_PARAMS_KEY in ckpt.keys(), "hyper_parameters missing from checkpoints"\n\n    # load new model\n    hparams_path = tutils.get_data_path(logger, path_dir=tmpdir)\n    hparams_path = os.path.join(hparams_path, "hparams.yaml")\n    ckpt_path = (\n        f"http://{tmpdir_server[0]}:{tmpdir_server[1]}/{os.path.basename(new_weights_path)}"\n        if url_ckpt else new_weights_path\n    )\n    model_2 = EvalModelTemplate.load_from_checkpoint(\n        checkpoint_path=ckpt_path,\n        hparams_file=hparams_path,\n    )\n    model_2.eval()\n\n\n@pytest.mark.parametrize("url_ckpt", [True, False])\ndef test_no_val_end_module(monkeypatch, tmpdir, tmpdir_server, url_ckpt):\n    """Tests use case where trainer saves the model, and user loads it from tags independently."""\n    # set $TORCH_HOME, which determines torch hub\'s cache path, to tmpdir\n    monkeypatch.setenv("TORCH_HOME", tmpdir)\n\n    model = EvalModelTemplate()\n\n    # logger file to get meta\n    logger = tutils.get_default_logger(tmpdir)\n\n    # fit model\n    trainer = Trainer(\n        default_root_dir=tmpdir,\n        max_epochs=1,\n        logger=logger,\n        callbacks=[ModelCheckpoint(dirpath=tmpdir)],\n    )\n    trainer.fit(model)\n\n    # traning complete\n    assert trainer.state == TrainerState.FINISHED, f"Training failed with {trainer.state}"\n\n    # save model\n    new_weights_path = os.path.join(tmpdir, "save_test.ckpt")\n    trainer.save_checkpoint(new_weights_path)\n\n    # load new model\n    hparams_path = tutils.get_data_path(logger, path_dir=tmpdir)\n    hparams_path = os.path.join(hparams_path, "hparams.yaml")\n    ckpt_path = (\n        f"http://{tmpdir_server[0]}:{tmpdir_server[1]}/{os.path.basename(new_weights_path)}"\n        if url_ckpt else new_weights_path\n    )\n    model_2 = EvalModelTemplate.load_from_checkpoint(\n        checkpoint_path=ckpt_path,\n        hparams_file=hparams_path,\n    )\n    model_2.eval()\n\n\n@pytest.mark.parametrize("url_ckpt", [True, False])\ndef test_strict_model_load(monkeypatch, tmpdir, tmpdir_server, url_ckpt):\n    """Tests use case where trainer saves the model, and user loads it from tags independently."""\n    # set $TORCH_HOME, which determines torch hub\'s cache path, to tmpdir\n    monkeypatch.setenv("TORCH_HOME", tmpdir)\n\n    model = EvalModelTemplate()\n    # Extra layer\n    model.c_d3 = torch.nn.Linear(model.hidden_dim, model.hidden_dim)\n\n    # logger file to get meta\n    logger = tutils.get_default_logger(tmpdir)\n\n    # fit model\n    trainer = Trainer(\n        default_root_dir=tmpdir,\n        max_epochs=1,\n        logger=logger,\n        callbacks=[ModelCheckpoint(dirpath=tmpdir)],\n    )\n    trainer.fit(model)\n\n    # traning complete\n    assert trainer.state == TrainerState.FINISHED, f"Training failed with {trainer.state}"\n    assert trainer.state == TrainerState.FINISHED\n\n    # save model\n    new_weights_path = os.path.join(tmpdir, "save_test.ckpt")\n    trainer.save_checkpoint(new_weights_path)\n\n    # load new model\n    hparams_path = tutils.get_data_path(logger, path_dir=tmpdir)\n    hparams_path = os.path.join(hparams_path, "hparams.yaml")\n    ckpt_path = (\n        f"http://{tmpdir_server[0]}:{tmpdir_server[1]}/{os.path.basename(new_weights_path)}"\n        if url_ckpt else new_weights_path\n    )\n\n    try:\n        EvalModelTemplate.load_from_checkpoint(\n            checkpoint_path=ckpt_path,\n            hparams_file=hparams_path,\n        )\n    # todo: specify the possible exception\n    except Exception:\n        failed = True\n    else:\n        failed = False\n\n    assert failed, "Model should not been loaded since the extra layer added."\n\n    failed = False\n    try:\n        EvalModelTemplate.load_from_checkpoint(\n            checkpoint_path=ckpt_path,\n            hparams_file=hparams_path,\n            strict=False,\n        )\n    # todo: specify the possible exception\n    except Exception:\n        failed = True\n\n    assert not failed, "Model should be loaded due to strict=False."\n\n\n@pytest.mark.parametrize("accumulate_grad_batches", (1, 2, 3))\ndef test_trainer_accumulate_grad_batches_zero_grad(tmpdir, accumulate_grad_batches):\n    with patch("torch.optim.SGD.zero_grad") as sgd_zero_grad:\n        model = BoringModel()\n        trainer = Trainer(\n            default_root_dir=tmpdir,\n            limit_train_batches=20,\n            limit_val_batches=1,\n            max_epochs=1,\n            weights_summary=None,\n            accumulate_grad_batches=accumulate_grad_batches,\n        )\n        trainer.fit(model)\n\n        assert sgd_zero_grad.call_count == math.ceil(trainer.limit_train_batches / accumulate_grad_batches)\n\n\n@pytest.mark.parametrize(\n    ["accumulate_grad_batches", "limit_train_batches"],\n    [\n        ({\n            1: 2,\n            3: 4\n        }, 1.0),\n        ({\n            1: 2,\n            3: 4\n        }, 0.5),  # not to be divisible by accumulate_grad_batches on purpose\n        (3, 1.0),\n        (3, 0.8),  # not to be divisible by accumulate_grad_batches on purpose\n        (4, 1.0),\n        (4, 0.7),  # not to be divisible by accumulate_grad_batches on purpose\n    ],\n)\ndef test_gradient_accumulation_scheduling_last_batch(tmpdir, accumulate_grad_batches, limit_train_batches):\n    """ Verify optimizer.step() applied to last batch while grad accumulation """\n\n    class CurrentModel(BoringModel):\n\n        def on_batch_start(self, *_):\n            self.on_train_batch_start_state_dict = self.state_dict()\n\n        def on_batch_end(self, outputs, batch, batch_idx, *_):\n            self.on_train_batch_start_end_dict = self.state_dict()\n            for key in self.on_train_batch_start_end_dict.keys():\n                equal = torch.equal(self.on_train_batch_start_state_dict[key], self.on_train_batch_start_end_dict[key])\n                if (batch_idx + 1) == self.trainer.num_training_batches:\n                    assert equal\n                else:\n                    assert not equal\n\n    model = CurrentModel()\n\n    trainer = Trainer(\n        accumulate_grad_batches=accumulate_grad_batches,\n        max_epochs=2,\n        limit_train_batches=limit_train_batches,\n        limit_val_batches=0,\n        limit_test_batches=0,\n        default_root_dir=tmpdir,\n    )\n\n    trainer.fit(model)\n\n\ndef test_loading_meta_tags(tmpdir):\n    """ test for backward compatibility to meta_tags.csv """\n    tutils.reset_seed()\n\n    hparams = EvalModelTemplate.get_default_hparams()\n\n    # save tags\n    logger = tutils.get_default_logger(tmpdir)\n    logger.log_hyperparams(Namespace(some_str="a_str", an_int=1, a_float=2.0))\n    logger.log_hyperparams(hparams)\n    logger.save()\n\n    # load hparams\n    path_expt_dir = tutils.get_data_path(logger, path_dir=tmpdir)\n    hparams_path = os.path.join(path_expt_dir, TensorBoardLogger.NAME_HPARAMS_FILE)\n    hparams = load_hparams_from_yaml(hparams_path)\n\n    # save as legacy meta_tags.csv\n    tags_path = os.path.join(path_expt_dir, "meta_tags.csv")\n    save_hparams_to_tags_csv(tags_path, hparams)\n\n    tags = load_hparams_from_tags_csv(tags_path)\n\n    assert hparams == tags\n\n\ndef test_loading_yaml(tmpdir):\n    tutils.reset_seed()\n\n    hparams = EvalModelTemplate.get_default_hparams()\n\n    # save tags\n    logger = tutils.get_default_logger(tmpdir)\n    logger.log_hyperparams(Namespace(some_str="a_str", an_int=1, a_float=2.0))\n    logger.log_hyperparams(hparams)\n    logger.save()\n\n    # load hparams\n    path_expt_dir = tutils.get_data_path(logger, path_dir=tmpdir)\n    hparams_path = os.path.join(path_expt_dir, "hparams.yaml")\n    tags = load_hparams_from_yaml(hparams_path)\n\n    assert tags["batch_size"] == 32 and tags["hidden_dim"] == 1000\n\n\n@pytest.mark.parametrize(\n    "save_top_k,save_last,expected_files",\n    [\n        pytest.param(-1, False, [f"epoch={i}.ckpt" for i in range(5)], id="CASE K=-1  (all)"),\n        pytest.param(1, False, {"epoch=4.ckpt"}, id="CASE K=1 (2.5, epoch 4)"),\n        pytest.param(2, False, [f"epoch={i}.ckpt" for i in (2, 4)], id="CASE K=2 (2.5 epoch 4, 2.8 epoch 2)"),\n        pytest.param(4, False, [f"epoch={i}.ckpt" for i in range(1, 5)], id="CASE K=4 (save all 4 base)"),\n        pytest.param(3, False, [f"epoch={i}.ckpt" for i in range(2, 5)], id="CASE K=3 (save the 2nd, 3rd, 4th model)"),\n        pytest.param(1, True, {"epoch=4.ckpt", "last.ckpt"}, id="CASE K=1 (save the 4th model and the last model)"),\n    ],\n)\ndef test_model_checkpoint_options(tmpdir, save_top_k, save_last, expected_files):\n    """Test ModelCheckpoint options."""\n\n    def mock_save_function(filepath, *args):\n        open(filepath, "a").close()\n\n    # simulated losses\n    losses = [10, 9, 2.8, 5, 2.5]\n\n    checkpoint_callback = ModelCheckpoint(\n        dirpath=tmpdir,\n        filename=\'{epoch}\',\n        monitor=\'checkpoint_on\',\n        save_top_k=save_top_k,\n        save_last=save_last,\n        verbose=True\n    )\n    checkpoint_callback.save_function = mock_save_function\n    trainer = Trainer()\n    trainer.state = TrainerState.FITTING\n\n    # emulate callback\'s calls during the training\n    for i, loss in enumerate(losses):\n        trainer.current_epoch = i\n        trainer.global_step = i\n        trainer.logger_connector.callback_metrics = {"checkpoint_on": torch.tensor(loss)}\n        checkpoint_callback.on_validation_end(trainer, trainer.lightning_module)\n\n    file_lists = set(os.listdir(tmpdir))\n\n    assert len(file_lists) == len(\n        expected_files\n    ), f"Should save {len(expected_files)} models when save_top_k={save_top_k} but found={file_lists}"\n\n    # verify correct naming\n    for fname in expected_files:\n        assert fname in file_lists\n\n\ndef test_model_checkpoint_only_weights(tmpdir):\n    """Tests use case where ModelCheckpoint is configured to save only model weights, and\n    user tries to load checkpoint to resume training.\n    """\n    model = EvalModelTemplate()\n\n    trainer = Trainer(\n        default_root_dir=tmpdir,\n        max_epochs=1,\n        callbacks=[ModelCheckpoint(dirpath=tmpdir, monitor=\'early_stop_on\', save_weights_only=True)],\n    )\n    # fit model\n    trainer.fit(model)\n    # training complete\n    assert trainer.state == TrainerState.FINISHED, f"Training failed with {trainer.state}"\n\n    checkpoint_path = list(trainer.checkpoint_callback.best_k_models.keys())[0]\n\n    # assert saved checkpoint has no trainer data\n    checkpoint = torch.load(checkpoint_path)\n    assert "optimizer_states" not in checkpoint, "checkpoint should contain only model weights"\n    assert "lr_schedulers" not in checkpoint, "checkpoint should contain only model weights"\n\n    # assert loading model works when checkpoint has only weights\n    assert EvalModelTemplate.load_from_checkpoint(checkpoint_path=checkpoint_path)\n\n    # directly save model\n    new_weights_path = os.path.join(tmpdir, "save_test.ckpt")\n    trainer.save_checkpoint(new_weights_path, weights_only=True)\n    # assert saved checkpoint has no trainer data\n    checkpoint = torch.load(new_weights_path)\n    assert "optimizer_states" not in checkpoint, "checkpoint should contain only model weights"\n    assert "lr_schedulers" not in checkpoint, "checkpoint should contain only model weights"\n\n    # assert restoring train state fails\n    with pytest.raises(KeyError, match="checkpoint contains only the model"):\n        trainer.checkpoint_connector.restore_training_state(checkpoint)\n\n\ndef test_model_freeze_unfreeze():\n    model = EvalModelTemplate()\n    model.freeze()\n    model.unfreeze()\n\n\n@pytest.mark.parametrize("url_ckpt", [True, False])\ndef test_resume_from_checkpoint_epoch_restored(monkeypatch, tmpdir, tmpdir_server, url_ckpt):\n    """Verify resuming from checkpoint runs the right number of epochs"""\n    # set $TORCH_HOME, which determines torch hub\'s cache path, to tmpdir\n    monkeypatch.setenv("TORCH_HOME", tmpdir)\n\n    class TestModel(BoringModel):\n        # Model that tracks epochs and batches seen\n        num_epochs_end_seen = 0\n        num_batches_seen = 0\n        num_on_load_checkpoint_called = 0\n\n        def on_epoch_end(self):\n            self.num_epochs_end_seen += 1\n\n        def on_train_batch_start(self, *_):\n            self.num_batches_seen += 1\n\n        def on_load_checkpoint(self, _):\n            self.num_on_load_checkpoint_called += 1\n\n    model = TestModel()\n    trainer = Trainer(\n        max_epochs=2,\n        limit_train_batches=0.65,\n        limit_val_batches=1,\n        callbacks=[ModelCheckpoint(dirpath=tmpdir, monitor=\'early_stop_on\', save_top_k=-1)],\n        default_root_dir=tmpdir,\n        val_check_interval=1.0,\n        progress_bar_refresh_rate=0,\n        logger=False,\n        weights_summary=None,\n    )\n    trainer.fit(model)\n\n    # `on_epoch_end` will be called once for val_sanity, twice for train, twice for val\n    assert model.num_epochs_end_seen == 1 + 2 + 2\n    assert model.num_batches_seen == trainer.num_training_batches * 2\n    assert model.num_on_load_checkpoint_called == 0\n\n    # Other checkpoints can be uncommented if/when resuming mid-epoch is supported\n    checkpoints = Path(trainer.checkpoint_callback.dirpath).glob("*.ckpt")\n    if url_ckpt:\n        # transform local paths into url checkpoints\n        ip, port = tmpdir_server\n        checkpoints = [f"http://{ip}:{port}/" + ckpt.name for ckpt in checkpoints]\n\n    for ckpt in checkpoints:\n        next_model = TestModel()\n        state = pl_load(ckpt)\n\n        # Resume training\n        new_trainer = Trainer(\n            default_root_dir=tmpdir,\n            resume_from_checkpoint=ckpt,\n            max_epochs=2,\n        )\n        new_trainer.fit(next_model)\n        assert state["global_step"] + next_model.num_batches_seen == trainer.num_training_batches * trainer.max_epochs\n        assert next_model.num_on_load_checkpoint_called == 1\n\n\ndef test_trainer_max_steps_and_epochs(tmpdir):\n    """Verify model trains according to specified max steps"""\n    model = BoringModel()\n    num_train_samples = math.floor(len(model.train_dataloader()) * 0.5)\n\n    # define less train steps than epochs\n    trainer_kwargs = {\n        \'limit_train_batches\': 0.5,\n        \'default_root_dir\': tmpdir,\n        \'max_epochs\': 3,\n        \'max_steps\': num_train_samples + 10,\n        \'logger\': False,\n        \'weights_summary\': None,\n        \'progress_bar_refresh_rate\': 0,\n    }\n    trainer = Trainer(**trainer_kwargs)\n    trainer.fit(model)\n\n    assert trainer.state == TrainerState.FINISHED, f"Training failed with {trainer.state}"\n    assert trainer.state == TrainerState.FINISHED\n    assert trainer.global_step == trainer.max_steps, "Model did not stop at max_steps"\n\n    # define less train epochs than steps\n    trainer_kwargs[\'max_epochs\'] = 2\n    trainer_kwargs[\'max_steps\'] = 3 * 2 * num_train_samples\n    trainer = Trainer(**trainer_kwargs)\n    trainer.fit(model)\n\n    assert trainer.state == TrainerState.FINISHED, f"Training failed with {trainer.state}"\n    assert trainer.global_step == num_train_samples * trainer.max_epochs\n    assert trainer.current_epoch == trainer.max_epochs - 1, "Model did not stop at max_epochs"\n\n\ndef test_trainer_min_steps_and_epochs(tmpdir):\n    """Verify model trains according to specified min steps"""\n    model = EvalModelTemplate()\n    num_train_samples = math.floor(len(model.train_dataloader()) * 0.5)\n\n    trainer_kwargs = {\n        \'limit_train_batches\': 0.5,\n        \'default_root_dir\': tmpdir,\n        # define callback for stopping the model\n        \'callbacks\': [EarlyStopping(monitor="early_stop_on", min_delta=1.0)],\n        \'val_check_interval\': 2,\n        \'min_epochs\': 1,\n        \'max_epochs\': 7,\n        # define less min steps than 1 epoch\n        \'min_steps\': num_train_samples // 2,\n        \'logger\': False,\n        \'weights_summary\': None,\n        \'progress_bar_refresh_rate\': 0,\n    }\n    trainer = Trainer(**trainer_kwargs)\n    trainer.fit(model)\n\n    assert trainer.state == TrainerState.FINISHED, f"Training failed with {trainer.state}"\n    assert trainer.state == TrainerState.FINISHED\n    assert trainer.current_epoch > 0\n    assert trainer.global_step >= num_train_samples, "Model did not train for at least min_epochs"\n\n    # define less epochs than min_steps\n    trainer_kwargs["min_steps"] = math.floor(num_train_samples * 1.5)\n    trainer = Trainer(**trainer_kwargs)\n    trainer.fit(model)\n\n    assert trainer.state == TrainerState.FINISHED, f"Training failed with {trainer.state}"\n    assert trainer.current_epoch > 0\n    assert trainer.global_step >= math.floor(num_train_samples * 1.5), "Model did not train for at least min_steps"\n\n\ndef test_trainer_min_steps_and_min_epochs_not_reached(tmpdir, caplog):\n    """ Test that min_epochs/min_steps in Trainer are enforced even if EarlyStopping is triggered. """\n\n    class TestModel(BoringModel):\n        training_step_invoked = 0\n\n        def training_step(self, batch, batch_idx):\n            output = super().training_step(batch, batch_idx)\n            output["loss"] = output["loss"] * 0.0  # force minimal loss to trigger early stopping\n            self.log("loss", output["loss"])\n            self.training_step_invoked += 1\n            assert not self.trainer.should_stop\n            return output\n\n    model = TestModel()\n    early_stop = EarlyStopping(monitor="loss", patience=0)\n    min_epochs = 5\n    trainer = Trainer(\n        default_root_dir=tmpdir,\n        progress_bar_refresh_rate=0,\n        min_epochs=min_epochs,\n        limit_val_batches=0,\n        limit_train_batches=2,\n        callbacks=[early_stop]\n    )\n    with caplog.at_level(logging.INFO, logger="pytorch_lightning.trainer.trainer"):\n        trainer.fit(model)\n\n    message = f"minimum epochs ({min_epochs}) or minimum steps (None) has not been met. Training will continue"\n    num_messages = len([record.message for record in caplog.records if message in record.message])\n    assert num_messages == min_epochs - 2\n    assert model.training_step_invoked == min_epochs * 2\n\n\ndef test_trainer_max_steps_accumulate_batches(tmpdir):\n    """Verify model trains according to specified max steps with grad accumulated batches"""\n    model = BoringModel()\n    num_train_samples = math.floor(len(model.train_dataloader()) * 0.5)\n\n    # define less train steps than epochs\n    trainer = Trainer(\n        limit_train_batches=0.5,\n        default_root_dir=tmpdir,\n        max_steps=num_train_samples + 10,\n        accumulate_grad_batches=10,\n        logger=False,\n        weights_summary=None,\n        progress_bar_refresh_rate=0,\n    )\n    trainer.fit(model)\n\n    assert trainer.state == TrainerState.FINISHED, f"Training failed with {trainer.state}"\n    assert trainer.state == TrainerState.FINISHED\n    assert trainer.global_step == trainer.max_steps, "Model did not stop at max_steps"\n\n\ndef test_benchmark_option(tmpdir):\n    """Verify benchmark option."""\n\n    model = EvalModelTemplate()\n    model.val_dataloader = model.val_dataloader__multiple\n\n    # verify torch.backends.cudnn.benchmark is not turned on\n    assert not torch.backends.cudnn.benchmark\n\n    # fit model\n    trainer = Trainer(\n        default_root_dir=tmpdir,\n        max_epochs=1,\n        benchmark=True,\n    )\n    trainer.fit(model)\n\n    # verify training completed\n    assert trainer.state == TrainerState.FINISHED, f"Training failed with {trainer.state}"\n\n    # verify torch.backends.cudnn.benchmark is not turned off\n    assert torch.backends.cudnn.benchmark\n\n\n@pytest.mark.parametrize("ckpt_path", (None, "best", "specific"))\n@pytest.mark.parametrize("save_top_k", (-1, 0, 1, 2))\n@pytest.mark.parametrize("fn", ("validate", "test"))\ndef test_tested_checkpoint_path(tmpdir, ckpt_path, save_top_k, fn):\n\n    class TestModel(BoringModel):\n\n        def validation_step(self, batch, batch_idx):\n            self.log("foo", -batch_idx)\n            return super().validation_step(batch, batch_idx)\n\n    model = TestModel()\n    trainer = Trainer(\n        max_epochs=2,\n        progress_bar_refresh_rate=0,\n        default_root_dir=tmpdir,\n        callbacks=[ModelCheckpoint(monitor="foo", save_top_k=save_top_k)],\n    )\n    trainer.fit(model)\n\n    test_or_validate = getattr(trainer, fn)\n    if ckpt_path == "best":\n        # ckpt_path is \'best\', meaning we load the best weights\n        if save_top_k == 0:\n            with pytest.raises(MisconfigurationException, match=".*is not configured to save the best.*"):\n                test_or_validate(ckpt_path=ckpt_path)\n        else:\n            test_or_validate(ckpt_path=ckpt_path)\n            if fn == "test":\n                assert trainer.tested_ckpt_path == trainer.checkpoint_callback.best_model_path\n            else:\n                assert trainer.validated_ckpt_path == trainer.checkpoint_callback.best_model_path\n    elif ckpt_path is None:\n        # ckpt_path is None, meaning we don\'t load any checkpoints and\n        # use the weights from the end of training\n        test_or_validate(ckpt_path=ckpt_path)\n        assert trainer.tested_ckpt_path is None\n        assert trainer.validated_ckpt_path is None\n    else:\n        # specific checkpoint, pick one from saved ones\n        if save_top_k == 0:\n            with pytest.raises(FileNotFoundError):\n                test_or_validate(ckpt_path="random.ckpt")\n        else:\n            ckpt_path = str(\n                list((Path(tmpdir) / f"lightning_logs/version_{trainer.logger.version}/checkpoints").iterdir()\n                     )[0].absolute()\n            )\n            test_or_validate(ckpt_path=ckpt_path)\n            if fn == "test":\n                assert trainer.tested_ckpt_path == ckpt_path\n            else:\n                assert trainer.validated_ckpt_path == ckpt_path\n\n\ndef test_disabled_training(tmpdir):\n    """Verify that `limit_train_batches=0` disables the training loop unless `fast_dev_run=True`."""\n\n    class CurrentModel(BoringModel):\n\n        training_step_invoked = False\n        training_epoch_end_invoked = False\n\n        def training_step(self, *args, **kwargs):\n            self.training_step_invoked = True\n            return super().training_step(*args, **kwargs)\n\n        def training_epoch_end(self, *args, **kwargs):\n            self.training_epoch_end_invoked = True\n            return super().training_epoch_end(*args, **kwargs)\n\n    model = CurrentModel()\n\n    trainer_options = dict(\n        default_root_dir=tmpdir,\n        progress_bar_refresh_rate=0,\n        max_epochs=2,\n        limit_train_batches=0.0,\n        limit_val_batches=0.2,\n        fast_dev_run=False,\n    )\n\n    before_state_dict = deepcopy(model.state_dict())\n\n    trainer = Trainer(**trainer_options)\n    trainer.fit(model)\n\n    after_state_dict = model.state_dict()\n\n    for key in before_state_dict.keys():\n        assert torch.all(torch.eq(before_state_dict[key], after_state_dict[key]))\n\n    # check that limit_train_batches=0 turns off training\n    assert trainer.state == TrainerState.FINISHED, f"Training failed with {trainer.state}"\n    assert trainer.current_epoch == 0\n    assert not model.training_step_invoked, "`training_step` should not run when `limit_train_batches=0`"\n    assert not model.training_epoch_end_invoked, "`training_epoch_end` should not run when `limit_train_batches=0`"\n\n    # check that limit_train_batches has no influence when fast_dev_run is turned on\n    model = CurrentModel()\n    trainer_options.update(fast_dev_run=True)\n    before_state_dict = deepcopy(model.state_dict())\n\n    trainer = Trainer(**trainer_options)\n    trainer.fit(model)\n\n    after_state_dict = model.state_dict()\n\n    for key in before_state_dict.keys():\n        assert not torch.all(torch.eq(before_state_dict[key], after_state_dict[key]))\n\n    assert trainer.state == TrainerState.FINISHED, f"Training failed with {trainer.state}"\n    assert trainer.current_epoch == 0\n    assert model.training_step_invoked, "did not run `training_step` with `fast_dev_run=True`"\n    assert model.training_epoch_end_invoked, "did not run `training_epoch_end` with `fast_dev_run=True`"\n\n\ndef test_disabled_validation(tmpdir):\n    """Verify that `limit_val_batches=0` disables the validation loop unless `fast_dev_run=True`."""\n\n    class CurrentModel(EvalModelTemplate):\n\n        validation_step_invoked = False\n        validation_epoch_end_invoked = False\n\n        def validation_step(self, *args, **kwargs):\n            self.validation_step_invoked = True\n            return super().validation_step(*args, **kwargs)\n\n        def validation_epoch_end(self, *args, **kwargs):\n            self.validation_epoch_end_invoked = True\n            return super().validation_epoch_end(*args, **kwargs)\n\n    hparams = EvalModelTemplate.get_default_hparams()\n    model = CurrentModel(**hparams)\n\n    trainer_options = dict(\n        default_root_dir=tmpdir,\n        progress_bar_refresh_rate=0,\n        max_epochs=2,\n        limit_train_batches=0.4,\n        limit_val_batches=0.0,\n        fast_dev_run=False,\n    )\n\n    trainer = Trainer(**trainer_options)\n    result = trainer.fit(model)\n\n    # check that limit_val_batches=0 turns off validation\n    assert result == 1, "training failed to complete"\n    assert trainer.state == TrainerState.FINISHED, f"Training failed with {trainer.state}"\n    assert trainer.current_epoch == 1\n    assert not model.validation_step_invoked, "`validation_step` should not run when `limit_val_batches=0`"\n    assert not model.validation_epoch_end_invoked, "`validation_epoch_end` should not run when `limit_val_batches=0`"\n\n    # check that limit_val_batches has no influence when fast_dev_run is turned on\n    model = CurrentModel(**hparams)\n    trainer_options.update(fast_dev_run=True)\n    trainer = Trainer(**trainer_options)\n    trainer.fit(model)\n\n    assert trainer.state == TrainerState.FINISHED, f"Training failed with {trainer.state}"\n    assert trainer.current_epoch == 0\n    assert model.validation_step_invoked, "did not run `validation_step` with `fast_dev_run=True`"\n    assert model.validation_epoch_end_invoked, "did not run `validation_epoch_end` with `fast_dev_run=True`"\n\n\ndef test_nan_loss_detection(tmpdir):\n\n    class CurrentModel(EvalModelTemplate):\n        test_batch_inf_loss = 8\n\n        def training_step(self, batch, batch_idx, optimizer_idx=None):\n            output = super().training_step(batch, batch_idx, optimizer_idx)\n            if batch_idx == self.test_batch_inf_loss:\n                if isinstance(output, dict):\n                    output["loss"] *= torch.tensor(math.inf)  # make loss infinite\n                else:\n                    output /= 0\n            return output\n\n    model = CurrentModel()\n\n    # fit model\n    trainer = Trainer(\n        default_root_dir=tmpdir,\n        max_steps=(model.test_batch_inf_loss + 1),\n        terminate_on_nan=True,\n    )\n\n    with pytest.raises(ValueError, match=r".*The loss returned in `training_step` is nan or inf.*"):\n        trainer.fit(model)\n        assert trainer.global_step == model.test_step_inf_loss\n\n    for param in model.parameters():\n        assert torch.isfinite(param).all()\n\n\ndef test_nan_params_detection(tmpdir):\n\n    class CurrentModel(EvalModelTemplate):\n        test_batch_nan = 8\n\n        def on_after_backward(self):\n            if self.global_step == self.test_batch_nan:\n                # simulate parameter that became nan\n                torch.nn.init.constant_(self.c_d1.bias, math.nan)\n\n    model = CurrentModel()\n    trainer = Trainer(\n        default_root_dir=tmpdir,\n        max_steps=(model.test_batch_nan + 1),\n        terminate_on_nan=True,\n    )\n\n    with pytest.raises(ValueError, match=r".*Detected nan and/or inf values in `c_d1.bias`.*"):\n        trainer.fit(model)\n        assert trainer.global_step == model.test_batch_nan\n\n    # after aborting the training loop, model still has nan-valued params\n    params = torch.cat([param.view(-1) for param in model.parameters()])\n    assert not torch.isfinite(params).all()\n\n\ndef test_trainer_interrupted_flag(tmpdir):\n    """Test the flag denoting that a user interrupted training."""\n\n    model = EvalModelTemplate()\n\n    class InterruptCallback(Callback):\n\n        def __init__(self):\n            super().__init__()\n\n        def on_train_batch_start(self, trainer, pl_module, batch, batch_idx, dataloader_idx):\n            raise KeyboardInterrupt\n\n    class HandleInterruptCallback(Callback):\n\n        def __init__(self):\n            super().__init__()\n            self.exc_info = None\n\n        def on_keyboard_interrupt(self, trainer, pl_module):\n            self.exc_info = sys.exc_info()\n\n    interrupt_callback = InterruptCallback()\n    handle_interrupt_callback = HandleInterruptCallback()\n\n    trainer = Trainer(\n        callbacks=[interrupt_callback, handle_interrupt_callback],\n        max_epochs=1,\n        limit_val_batches=0.1,\n        limit_train_batches=0.2,\n        progress_bar_refresh_rate=0,\n        logger=False,\n        default_root_dir=tmpdir,\n    )\n    assert not trainer.interrupted\n    assert handle_interrupt_callback.exc_info is None\n    trainer.fit(model)\n    assert trainer.interrupted\n    assert isinstance(handle_interrupt_callback.exc_info[1], KeyboardInterrupt)\n\n\ndef test_gradient_clipping(tmpdir):\n    """\n    Test gradient clipping\n    """\n    tutils.reset_seed()\n\n    model = EvalModelTemplate()\n\n    trainer = Trainer(\n        max_steps=1,\n        max_epochs=1,\n        gradient_clip_val=1.0,\n        default_root_dir=tmpdir,\n    )\n\n    trainer.train_loop.old_training_step_and_backward = trainer.train_loop.training_step_and_backward\n\n    def training_step_and_backward(split_batch, batch_idx, opt_idx, optimizer, hiddens):\n        """\n        wrap the forward step in a closure so second order methods work\n        """\n        # test that gradient is clipped correctly\n        ret_val = trainer.train_loop.old_training_step_and_backward(split_batch, batch_idx, opt_idx, optimizer, hiddens)\n        parameters = model.parameters()\n        grad_norm = torch.norm(torch.stack([torch.norm(p.grad.detach(), 2) for p in parameters]), 2)\n        assert (grad_norm - 1.0).abs() < 0.01, "Gradient norm != 1.0: {grad_norm}".format(grad_norm=grad_norm)\n\n        return ret_val\n\n    trainer.train_loop.training_step_and_backward = training_step_and_backward\n    # for the test\n    model.prev_called_batch_idx = 0\n\n    trainer.fit(model)\n\n\ndef test_gradient_clipping_by_value(tmpdir):\n    """\n    Test gradient clipping by value\n    """\n    tutils.reset_seed()\n\n    model = BoringModel()\n\n    grad_clip_val = 0.0001\n    trainer = Trainer(\n        max_steps=10,\n        max_epochs=1,\n        gradient_clip_val=grad_clip_val,\n        gradient_clip_algorithm=\'value\',\n        default_root_dir=tmpdir,\n    )\n\n    trainer.train_loop.old_training_step_and_backward = trainer.train_loop.training_step_and_backward\n\n    def training_step_and_backward(split_batch, batch_idx, opt_idx, optimizer, hiddens):\n        """\n        wrap the forward step in a closure so second order methods work\n        """\n        # test that gradient is clipped correctly\n        ret_val = trainer.train_loop.old_training_step_and_backward(split_batch, batch_idx, opt_idx, optimizer, hiddens)\n        parameters = model.parameters()\n        grad_max_list = [torch.max(p.grad.detach().abs()) for p in parameters]\n        grad_max = torch.max(torch.stack(grad_max_list))\n        assert round(grad_max.item(), 6) <= grad_clip_val, \\\n            f"Gradient max value {grad_max} > grad_clip_val {grad_clip_val} ."\n\n        return ret_val\n\n    trainer.train_loop.training_step_and_backward = training_step_and_backward\n    # for the test\n    model.prev_called_batch_idx = 0\n\n    trainer.fit(model)\n\n\n@RunIf(min_gpus=1, amp_native=True)\ndef test_gradient_clipping_fp16(tmpdir):\n    """\n    Test gradient clipping with fp16\n    """\n    tutils.reset_seed()\n\n    model = EvalModelTemplate()\n\n    trainer = Trainer(\n        max_steps=1,\n        max_epochs=1,\n        precision=16,\n        gpus=1,\n        gradient_clip_val=1.0,\n        default_root_dir=tmpdir,\n    )\n\n    trainer.train_loop.old_training_step_and_backward = trainer.train_loop.training_step_and_backward\n\n    def training_step_and_backward(split_batch, batch_idx, opt_idx, optimizer, hiddens):\n        """\n        wrap the forward step in a closure so second order methods work\n        """\n        # test that gradient is clipped correctly\n        ret_val = trainer.train_loop.old_training_step_and_backward(split_batch, batch_idx, opt_idx, optimizer, hiddens)\n        parameters = model.parameters()\n        grad_norm = torch.norm(torch.stack([torch.norm(p.grad.detach(), 2) for p in parameters]), 2)\n        assert (grad_norm - 1.0).abs() < 0.01, "Gradient norm != 1.0: {grad_norm}".format(grad_norm=grad_norm)\n\n        return ret_val\n\n    trainer.train_loop.training_step_and_backward = training_step_and_backward\n    model.prev_called_batch_idx = 0\n\n    trainer.fit(model)\n\n\n@RunIf(min_gpus=1, amp_native=True)\ndef test_gradient_clipping_by_value_fp16(tmpdir):\n    """\n    Test gradient clipping by value with fp16\n    """\n    tutils.reset_seed()\n\n    model = BoringModel()\n    grad_clip_val = 0.0001\n    trainer = Trainer(\n        max_steps=10,\n        max_epochs=1,\n        precision=16,\n        gpus=1,\n        gradient_clip_val=grad_clip_val,\n        gradient_clip_algorithm=\'value\',\n        default_root_dir=tmpdir,\n    )\n\n    trainer.train_loop.old_training_step_and_backward = trainer.train_loop.training_step_and_backward\n\n    def training_step_and_backward(split_batch, batch_idx, opt_idx, optimizer, hiddens):\n        """\n        wrap the forward step in a closure so second order methods work\n        """\n        # test that gradient is clipped correctly\n        ret_val = trainer.train_loop.old_training_step_and_backward(split_batch, batch_idx, opt_idx, optimizer, hiddens)\n        parameters = model.parameters()\n        grad_max = torch.max(torch.stack([p.grad.detach() for p in parameters]))\n        assert round(grad_max.item(), 6) <= grad_clip_val, \\\n            f"Gradient max value {grad_max} > grad_clip_val {grad_clip_val} ."\n\n        return ret_val\n\n    trainer.train_loop.training_step_and_backward = training_step_and_backward\n    model.prev_called_batch_idx = 0\n\n    trainer.fit(model)\n\n\ndef test_gpu_choice(tmpdir):\n    trainer_options = dict(default_root_dir=tmpdir)\n    # Only run if CUDA is available\n    if not torch.cuda.is_available():\n        return\n\n    num_gpus = torch.cuda.device_count()\n    Trainer(**trainer_options, gpus=num_gpus, auto_select_gpus=True)\n\n    with pytest.raises(RuntimeError, match=r".*No GPUs available.*"):\n        Trainer(**trainer_options, gpus=num_gpus + 1, auto_select_gpus=True)\n\n\n@pytest.mark.parametrize(\n    ["limit_val_batches"],\n    [\n        pytest.param(0.0),  # this should run no sanity checks\n        pytest.param(1),\n        pytest.param(1.0),\n        pytest.param(0.5),\n        pytest.param(5),\n    ],\n)\ndef test_num_sanity_val_steps(tmpdir, limit_val_batches):\n    """\n    Test that the number of sanity check batches is clipped to `limit_val_batches`.\n    """\n    model = EvalModelTemplate()\n    model.validation_step = model.validation_step__multiple_dataloaders\n    model.validation_epoch_end = model.validation_epoch_end__multiple_dataloaders\n    num_sanity_val_steps = 4\n\n    trainer = Trainer(\n        default_root_dir=tmpdir,\n        num_sanity_val_steps=num_sanity_val_steps,\n        limit_val_batches=limit_val_batches,\n        max_steps=1,\n    )\n    assert trainer.num_sanity_val_steps == num_sanity_val_steps\n\n    with patch.object(\n        trainer.evaluation_loop, "evaluation_step", wraps=trainer.evaluation_loop.evaluation_step\n    ) as mocked:\n        val_dataloaders = model.val_dataloader__multiple_mixed_length()\n        trainer.fit(model, val_dataloaders=val_dataloaders)\n\n        assert mocked.call_count == sum(\n            min(num_sanity_val_steps, num_batches) for num_batches in trainer.num_val_batches\n        )\n\n\n@pytest.mark.parametrize(\n    ["limit_val_batches"],\n    [\n        pytest.param(0.0),  # this should run no sanity checks\n        pytest.param(1),\n        pytest.param(1.0),\n        pytest.param(0.3),\n    ],\n)\ndef test_num_sanity_val_steps_neg_one(tmpdir, limit_val_batches):\n    """\n    Test that `num_sanity_val_steps=-1` runs through all validation data once, and as many batches as\n    limited by `limit_val_batches` Trainer argument.\n    """\n    model = EvalModelTemplate()\n    model.validation_step = model.validation_step__multiple_dataloaders\n    model.validation_epoch_end = model.validation_epoch_end__multiple_dataloaders\n    trainer = Trainer(\n        default_root_dir=tmpdir,\n        num_sanity_val_steps=-1,\n        limit_val_batches=limit_val_batches,\n        max_steps=1,\n    )\n    assert trainer.num_sanity_val_steps == float("inf")\n\n    with patch.object(\n        trainer.evaluation_loop, "evaluation_step", wraps=trainer.evaluation_loop.evaluation_step\n    ) as mocked:\n        val_dataloaders = model.val_dataloader__multiple()\n        trainer.fit(model, val_dataloaders=val_dataloaders)\n\n        assert mocked.call_count == sum(trainer.num_val_batches)\n\n\n@pytest.mark.parametrize(\n    "trainer_kwargs,expected",\n    [\n        (\n            dict(accelerator=None, gpus=None),\n            dict(\n                use_dp=False,\n                use_ddp=False,\n                use_ddp2=False,\n                num_gpus=0,\n                on_gpu=False,\n                use_single_gpu=False,\n                num_processes=1,\n            ),\n        ),\n        (\n            dict(accelerator="dp", gpus=None),\n            dict(\n                use_dp=False,\n                use_ddp=False,\n                use_ddp2=False,\n                num_gpus=0,\n                on_gpu=False,\n                use_single_gpu=False,\n                num_processes=1,\n            ),\n        ),\n        (\n            dict(accelerator="dp", gpus=None),\n            dict(\n                use_dp=False,\n                use_ddp=False,\n                use_ddp2=False,\n                num_gpus=0,\n                on_gpu=False,\n                use_single_gpu=False,\n                num_processes=1,\n            ),\n        ),\n        (\n            dict(accelerator="ddp", gpus=None),\n            dict(\n                use_dp=False,\n                use_ddp=False,\n                use_ddp2=False,\n                num_gpus=0,\n                on_gpu=False,\n                use_single_gpu=False,\n                num_processes=1,\n            ),\n        ),\n        (\n            dict(accelerator="ddp", num_processes=2, gpus=None),\n            dict(\n                use_dp=False,\n                use_ddp=True,\n                use_ddp2=False,\n                num_gpus=0,\n                on_gpu=False,\n                use_single_gpu=False,\n                num_processes=2,\n            ),\n        ),\n        (\n            dict(accelerator="ddp", num_nodes=2, gpus=None),\n            dict(\n                use_dp=False,\n                use_ddp=True,\n                use_ddp2=False,\n                num_gpus=0,\n                on_gpu=False,\n                use_single_gpu=False,\n                num_processes=1,\n            ),\n        ),\n        (\n            dict(accelerator="ddp_cpu", num_processes=2, gpus=None),\n            dict(\n                use_dp=False,\n                use_ddp=True,\n                use_ddp2=False,\n                num_gpus=0,\n                on_gpu=False,\n                use_single_gpu=False,\n                num_processes=2,\n            ),\n        ),\n        (\n            dict(accelerator="ddp2", gpus=None),\n            dict(\n                use_dp=False,\n                use_ddp=False,\n                use_ddp2=False,\n                num_gpus=0,\n                on_gpu=False,\n                use_single_gpu=False,\n                num_processes=1,\n            ),\n        ),\n        (\n            dict(accelerator=None, gpus=1),\n            dict(\n                use_dp=False,\n                use_ddp=False,\n                use_ddp2=False,\n                num_gpus=1,\n                on_gpu=True,\n                use_single_gpu=True,\n                num_processes=1,\n            ),\n        ),\n        (\n            dict(accelerator="dp", gpus=1),\n            dict(\n                use_dp=True,\n                use_ddp=False,\n                use_ddp2=False,\n                num_gpus=1,\n                on_gpu=True,\n                use_single_gpu=True,\n                num_processes=1,\n            ),\n        ),\n        (\n            dict(accelerator="ddp", gpus=1),\n            dict(\n                use_dp=False,\n                use_ddp=True,\n                use_ddp2=False,\n                num_gpus=1,\n                on_gpu=True,\n                use_single_gpu=True,\n                num_processes=1,\n            ),\n        ),\n        (\n            dict(accelerator="ddp_cpu", num_processes=2, gpus=1),\n            dict(\n                use_dp=False,\n                use_ddp=True,\n                use_ddp2=False,\n                num_gpus=0,\n                on_gpu=False,\n                use_single_gpu=False,\n                num_processes=2,\n            ),\n        ),\n        (\n            dict(accelerator="ddp2", gpus=1),\n            dict(\n                use_dp=False,\n                use_ddp=False,\n                use_ddp2=True,\n                num_gpus=1,\n                on_gpu=True,\n                use_single_gpu=False,\n                num_processes=1,\n            ),\n        ),\n        (\n            dict(accelerator=None, gpus=2),\n            dict(\n                use_dp=False,\n                use_ddp=True,\n                use_ddp2=False,\n                num_gpus=2,\n                on_gpu=True,\n                use_single_gpu=False,\n                num_processes=2,\n            ),\n        ),\n        (\n            dict(accelerator="dp", gpus=2),\n            dict(\n                use_dp=True,\n                use_ddp=False,\n                use_ddp2=False,\n                num_gpus=2,\n                on_gpu=True,\n                use_single_gpu=False,\n                num_processes=1,\n            ),\n        ),\n        (\n            dict(accelerator="ddp", gpus=2),\n            dict(\n                use_dp=False,\n                use_ddp=True,\n                use_ddp2=False,\n                num_gpus=2,\n                on_gpu=True,\n                use_single_gpu=False,\n                num_processes=2,\n            ),\n        ),\n        (\n            dict(accelerator="ddp2", gpus=2),\n            dict(\n                use_dp=False,\n                use_ddp=False,\n                use_ddp2=True,\n                num_gpus=2,\n                on_gpu=True,\n                use_single_gpu=False,\n                num_processes=1,\n            ),\n        ),\n    ],\n)\ndef test_trainer_config(trainer_kwargs, expected, monkeypatch):\n    if trainer_kwargs["gpus"] is not None:\n        monkeypatch.setattr(torch.cuda, "is_available", lambda: True)\n        monkeypatch.setattr(torch.cuda, "device_count", lambda: trainer_kwargs["gpus"])\n    trainer = Trainer(**trainer_kwargs)\n    assert len(expected) == 7\n    for k, v in expected.items():\n        assert getattr(trainer, k) == v, f"Failed {k}: {v}"\n\n\ndef test_trainer_subclassing():\n    model = EvalModelTemplate()\n\n    # First way of pulling out args from signature is to list them\n    class TrainerSubclass(Trainer):\n\n        def __init__(self, custom_arg, *args, custom_kwarg="test", **kwargs):\n            super().__init__(*args, **kwargs)\n            self.custom_arg = custom_arg\n            self.custom_kwarg = custom_kwarg\n\n    trainer = TrainerSubclass(123, custom_kwarg="custom", fast_dev_run=True)\n    trainer.fit(model)\n    assert trainer.state == TrainerState.FINISHED, f"Training failed with {trainer.state}"\n    assert trainer.custom_arg == 123\n    assert trainer.custom_kwarg == "custom"\n    assert trainer.fast_dev_run\n\n    # Second way is to pop from the dict\n    # It\'s a special case because Trainer does not have any positional args\n    class TrainerSubclass(Trainer):\n\n        def __init__(self, **kwargs):\n            self.custom_arg = kwargs.pop("custom_arg", 0)\n            self.custom_kwarg = kwargs.pop("custom_kwarg", "test")\n            super().__init__(**kwargs)\n\n    trainer = TrainerSubclass(custom_kwarg="custom", fast_dev_run=True)\n    trainer.fit(model)\n    assert trainer.state == TrainerState.FINISHED, f"Training failed with {trainer.state}"\n    assert trainer.custom_kwarg == "custom"\n    assert trainer.fast_dev_run\n\n    # when we pass in an unknown arg, the base class should complain\n    with pytest.raises(TypeError, match=r"__init__\\(\\) got an unexpected keyword argument \'abcdefg\'"):\n        TrainerSubclass(abcdefg="unknown_arg")\n\n\n@pytest.mark.parametrize(\n    "trainer_params",\n    [\n        OmegaConf.create({\n            "max_epochs": 1,\n            "gpus": 1\n        }),\n        OmegaConf.create({\n            "max_epochs": 1,\n            "gpus": [0]\n        }),\n    ],\n)\n@RunIf(min_gpus=1)\ndef test_trainer_omegaconf(trainer_params):\n    Trainer(**trainer_params)\n\n\ndef test_trainer_pickle(tmpdir):\n    trainer = Trainer(\n        max_epochs=1,\n        default_root_dir=tmpdir,\n    )\n    pickle.dumps(trainer)\n    cloudpickle.dumps(trainer)\n\n\n@pytest.mark.parametrize("stage", ("fit", "validate", "test"))\ndef test_trainer_setup_call(tmpdir, stage):\n    """Test setup call gets the correct stage"""\n\n    class CurrentModel(BoringModel):\n\n        def setup(self, stage):\n            self.stage = stage\n\n    class TrainerSubclass(Trainer):\n\n        def setup(self, model, stage):\n            assert model is not None\n            self.stage = stage\n\n    model = CurrentModel()\n\n    # fit model\n    trainer = TrainerSubclass(default_root_dir=tmpdir, max_epochs=1, checkpoint_callback=False)\n\n    if stage == "fit":\n        trainer.fit(model)\n    elif stage == "validate":\n        trainer.validate(model, ckpt_path=None)\n    else:\n        trainer.test(model, ckpt_path=None)\n\n    assert trainer.stage == stage\n    assert trainer.lightning_module.stage == stage\n\n\n@pytest.mark.parametrize(\n    "train_batches, max_steps, log_interval",\n    [\n        (10, 10, 1),\n        (3, 10, 1),\n        (3, 10, 5),\n    ],\n)\n@patch("pytorch_lightning.loggers.tensorboard.TensorBoardLogger.log_metrics")\ndef test_log_every_n_steps(log_metrics_mock, tmpdir, train_batches, max_steps, log_interval):\n    class TestModel(BoringModel):\n        def training_step(self, *args, **kwargs):\n            self.log("foo", -1)\n            return super().training_step(*args, **kwargs)\n\n    model = TestModel()\n    trainer = Trainer(\n        default_root_dir=tmpdir,\n        log_every_n_steps=log_interval,\n        flush_logs_every_n_steps=log_interval,\n        limit_train_batches=train_batches,\n        limit_val_batches=0,\n        max_steps=max_steps,\n    )\n    trainer.fit(model)\n    expected_calls = [call(metrics=ANY, step=s) for s in range(log_interval - 1, max_steps, log_interval)]\n    log_metrics_mock.assert_has_calls(expected_calls)\n\n\n@pytest.mark.parametrize([\'profiler\', \'expected\'], [\n    (None, PassThroughProfiler),\n    (SimpleProfiler(), SimpleProfiler),\n    (AdvancedProfiler(), AdvancedProfiler),\n    (\'simple\', SimpleProfiler),\n    (\'Simple\', SimpleProfiler),\n    (\'advanced\', AdvancedProfiler),\n    (\'pytorch\', PyTorchProfiler),\n])\ndef test_trainer_profiler_correct_args(profiler, expected):\n    kwargs = {\'profiler\': profiler} if profiler is not None else {}\n    trainer = Trainer(**kwargs)\n    assert isinstance(trainer.profiler, expected)\n\n\ndef test_trainer_profiler_incorrect_str_arg():\n    with pytest.raises(ValueError, match=r".*can only be \'simple\' or \'advanced\'"):\n        Trainer(profiler="unknown_profiler")\n\n\n@pytest.mark.parametrize(\'profiler\', (\n    42,\n    [42],\n    dict(a=42),\n    torch.tensor(42),\n    Trainer(),\n))\ndef test_trainer_profiler_incorrect_arg_type(profiler):\n    with pytest.raises(\n        MisconfigurationException,\n        match="Only None, str and subclasses of `BaseProfiler`"\n        r" are valid values for `Trainer`\'s `profiler` parameter. *"\n    ):\n        Trainer(profiler=profiler)\n\n\nclass TestLightningDataModule(LightningDataModule):\n\n    def __init__(self, dataloaders):\n        super().__init__()\n        self._dataloaders = dataloaders\n\n    def test_dataloader(self):\n        return self._dataloaders\n\n    def predict_dataloader(self):\n        return self._dataloaders\n\n\ndef predict(tmpdir, accelerator, gpus, num_processes, model=None, plugins=None, datamodule=True):\n\n    dataloaders = [torch.utils.data.DataLoader(RandomDataset(32, 2)), torch.utils.data.DataLoader(RandomDataset(32, 2))]\n\n    model = model or BoringModel()\n    dm = TestLightningDataModule(dataloaders)\n\n    trainer = Trainer(\n        default_root_dir=tmpdir,\n        max_epochs=1,\n        log_every_n_steps=1,\n        weights_summary=None,\n        accelerator=accelerator,\n        gpus=gpus,\n        num_processes=num_processes,\n        plugins=plugins,\n    )\n    if datamodule:\n        results = trainer.predict(model, datamodule=dm)\n    else:\n        results = trainer.predict(model, dataloaders=dataloaders)\n\n    # todo: address this in another PR\n    num_samples = 1 if accelerator in ["ddp", "ddp_cpu", "ddp_spawn"] else 2\n    assert len(results) == 2\n    assert len(results[0]) == num_samples\n    assert results[0][0].shape == torch.Size([1, 2])\n\n\ndef test_trainer_predict_no_return(tmpdir):\n    """\n    Test trainer.predict warns when nothing is returned\n    """\n\n    class CustomBoringModel(BoringModel):\n\n        def predict_step(self, batch, batch_idx, dataloader_idx=None):\n            if (batch_idx + 1) % 2 == 0:\n                return\n\n            return super().predict_step(batch, batch_idx, dataloader_idx)\n\n    with pytest.warns(UserWarning, match=\'predict returned None\'):\n        predict(tmpdir, None, None, 1, model=CustomBoringModel())\n\n\ndef test_trainer_predict_grad(tmpdir):\n\n    class CustomBoringModel(BoringModel):\n\n        def predict_step(self, batch, batch_idx, dataloader_idx=None):\n            assert batch.expand_as(batch).grad_fn is None\n            return super().predict_step(batch, batch_idx, dataloader_idx)\n\n    predict(tmpdir, None, None, 1, model=CustomBoringModel())\n\n    x = torch.zeros(1, requires_grad=True)\n    assert x.expand_as(x).grad_fn is not None\n\n\n@pytest.mark.parametrize(\'datamodule\', [False, True])\ndef test_trainer_predict_cpu(tmpdir, datamodule):\n    predict(tmpdir, None, None, 1, datamodule=datamodule)\n\n\n@RunIf(min_gpus=2, special=True)\n@pytest.mark.parametrize(\'num_gpus\', [1, 2])\ndef test_trainer_predict_dp(tmpdir, num_gpus):\n    predict(tmpdir, "dp", num_gpus, None)\n\n\n@RunIf(min_gpus=2, special=True, fairscale=True)\ndef test_trainer_predict_ddp(tmpdir):\n    predict(tmpdir, "ddp", 2, None, plugins=["ddp_sharded"])\n\n\n@RunIf(min_gpus=2, skip_windows=True, special=True)\ndef test_trainer_predict_ddp_spawn(tmpdir):\n    predict(tmpdir, "ddp_spawn", 2, None)\n\n\n@RunIf(min_gpus=2, special=True)\ndef test_trainer_predict_1_gpu(tmpdir):\n    predict(tmpdir, None, 1, None)\n\n\n@RunIf(skip_windows=True, special=True)\ndef test_trainer_predict_ddp_cpu(tmpdir):\n    predict(tmpdir, "ddp_cpu", 0, 2)\n\n\n@pytest.mark.parametrize(\n    ["limit_train_batches", "global_step", "num_training_batches", "current_epoch", "should_train"],\n    [(0.2, 0, 0, 0, False), (0.5, 10, 2, 4, True)],\n)\ndef test_disabled_training_for_insufficient_limit_train_batches(\n    tmpdir, limit_train_batches, global_step, num_training_batches, current_epoch, should_train\n):\n    """\n    Verify when `limit_train_batches` is float & between [0.0, 1.0] and\n    `int(self.num_training_batches * self.limit_train_batches) == 0`, the training loop is disabled.\n    """\n\n    class CurrentModel(BoringModel):\n\n        training_step_invoked = False\n        training_epoch_end_invoked = False\n\n        def training_step(self, *args, **kwargs):\n            self.training_step_invoked = True\n            return super().training_step(*args, **kwargs)\n\n        def training_epoch_end(self, *args, **kwargs):\n            self.training_epoch_end_invoked = True\n            return super().training_epoch_end(*args, **kwargs)\n\n    dataset_len = 100\n    batch_size = 25\n\n    train = RandomDataset(32, length=dataset_len)\n    train_loader = DataLoader(train, batch_size=batch_size)\n\n    model = CurrentModel()\n\n    trainer = Trainer(\n        default_root_dir=tmpdir,\n        max_epochs=5,\n        limit_train_batches=limit_train_batches,\n    )\n    result = trainer.fit(model, train_loader)\n\n    params_string = f"""`limit_train_batches={limit_train_batches}`, `dataset_len={dataset_len}`\n                        & `batch_size={batch_size}` as\n                        `num_training_batches={num_training_batches}`"""\n    if should_train:\n        error_string = f"should run with {params_string}"\n    else:\n        error_string = f"should not run with {params_string}"\n\n    assert result == 1, "training failed to complete"\n    assert trainer.state == TrainerState.FINISHED\n    assert trainer.global_step == global_step\n    assert trainer.num_training_batches == num_training_batches\n    assert trainer.current_epoch == current_epoch\n    assert model.training_step_invoked == should_train, f"`training_step` {error_string}"\n    assert model.training_epoch_end_invoked == should_train, f"`training_epoch_end` {error_string}"\n\n\n@pytest.mark.parametrize(["max_steps", "max_epochs", "global_step"], [(10, 5, 10), (20, None, 20)])\ndef test_repeated_fit_calls_with_max_epochs_and_steps(tmpdir, max_steps, max_epochs, global_step):\n    """\n    Ensure that the training loop is bound by `max_steps` and\n    `max_epochs` for repeated calls of `trainer.fit`, and\n    disabled if the limit is reached\n    """\n\n    dataset_len = 200\n    batch_size = 10\n\n    train_data = DataLoader(RandomDataset(32, dataset_len), batch_size=batch_size)\n\n    model = BoringModel()\n\n    trainer = Trainer(\n        default_root_dir=tmpdir,\n        max_steps=max_steps,\n        max_epochs=max_epochs,\n    )\n    trainer.fit(model, train_data)\n    assert trainer.global_step == global_step\n    trainer.fit(model, train_data)\n    assert trainer.global_step == global_step\n\n\ndef test_trainer_access_in_configure_optimizers(tmpdir):\n    """\n    Verify that the configure optimizer function can reference the trainer.\n    """\n\n    class TestModel(BoringModel):\n\n        def configure_optimizers(self):\n            assert self.trainer is not None, "Expect to have access to the trainer within `configure_optimizers`"\n\n    train_data = torch.utils.data.DataLoader(RandomDataset(32, 64))\n\n    model = TestModel()\n    trainer = Trainer(default_root_dir=tmpdir, fast_dev_run=True)\n    trainer.fit(model, train_data)\n\n\n@RunIf(min_gpus=1)\ndef test_setup_hook_move_to_device_correctly(tmpdir):\n    """\n    Verify that if a user defines a layer in the setup hook function, this is moved to the correct device.\n    """\n\n    class TestModel(BoringModel):\n\n        def setup(self, stage: str) -> None:\n            self.new_layer = torch.nn.Linear(2, 2)\n\n        def training_step(self, batch, batch_idx):\n            output = self.layer(batch)\n            # will crash if not moved to correct device\n            output = self.new_layer(output)\n            loss = self.loss(batch, output)\n            return {"loss": loss}\n\n    # fake data\n    train_data = torch.utils.data.DataLoader(RandomDataset(32, 64))\n\n    # model\n    model = TestModel()\n    trainer = Trainer(default_root_dir=tmpdir, fast_dev_run=True, gpus=1)\n    trainer.fit(model, train_data)\n\n\ndef test_train_loop_system(tmpdir):\n    """\n    Test the following methods are called in the order in automatic optimization.\n    1. optimizer.step (skip when gradient accumulation)\n    2. model.training_step\n    3. optimizer.zero_grad (run when the first batch of gradient accumulation)\n    4. model.backward\n\n    Note that the order is NOT `training_step`->`zero_grad`->`backward`->`step`.\n    This is because `optimizer.step(closure)` calls `closure()` which then calls\n    the three remaining methods `training_step`, `zero_grad` and `backward` inside.\n    """\n    called_methods = []\n\n    trainer_options = dict(\n        default_root_dir=tmpdir,\n        max_epochs=1,\n        limit_train_batches=5,\n        limit_val_batches=1,\n        limit_test_batches=1,\n        progress_bar_refresh_rate=0,\n    )\n\n    class TestOptimizer(SGD):\n\n        def step(self, *args, **kwargs):\n            called_methods.append("step")\n            return super().step(*args, **kwargs)\n\n        def zero_grad(self, *args, **kwargs):\n            called_methods.append("zero_grad")\n            return super().zero_grad(*args, **kwargs)\n\n    class TestModel(BoringModel):\n\n        def configure_optimizers(self):\n            return TestOptimizer(self.parameters(), lr=0.1)\n\n        def training_step(self, *args, **kwargs):\n            called_methods.append("training_step")\n            return super().training_step(*args, **kwargs)\n\n        def backward(self, *args, **kwargs):\n            called_methods.append("backward")\n            return super().backward(*args, **kwargs)\n\n    model = TestModel()\n    trainer = Trainer(**trainer_options)\n\n    # No methods are called yet.\n    assert called_methods == []\n\n    trainer.fit(model)\n    assert called_methods == [\n        "step",\n        "training_step",\n        "zero_grad",\n        "backward",\n    ] * trainer.limit_train_batches\n\n    called_methods.clear()\n    trainer = Trainer(**trainer_options, accumulate_grad_batches=3)\n\n    # No methods are called yet.\n    assert called_methods == []\n\n    trainer.fit(model)\n    assert called_methods == [\n        # 0\n        "training_step",\n        "zero_grad",\n        "backward",\n        # 1\n        "training_step",\n        "backward",\n        # 2\n        "step",\n        "training_step",\n        "backward",\n        # 3\n        "training_step",\n        "zero_grad",\n        "backward",\n        # 4\n        "step",\n        "training_step",\n        "backward",\n    ]\n\n\ndef test_init_optimizers_resets_lightning_optimizers(tmpdir):\n    """ Test that the Trainer resets the `lightning_optimizers` list everytime new optimizers get initialized. """\n\n    def compare_optimizers():\n        assert trainer.lightning_optimizers[0].optimizer is trainer.optimizers[0]\n\n    model = BoringModel()\n    model.lr = 0.2\n    trainer = Trainer(\n        default_root_dir=tmpdir,\n        max_epochs=1,\n        auto_lr_find=True,\n    )\n\n    trainer.tune(model)\n    compare_optimizers()\n\n    trainer.fit(model)\n    compare_optimizers()\n\n    trainer.max_epochs = 2  # simulate multiple fit calls\n    trainer.fit(model)\n    compare_optimizers()\n\n\ndef test_check_val_every_n_epoch_exception(tmpdir):\n\n    with pytest.raises(MisconfigurationException, match="should be an integer."):\n        Trainer(\n            default_root_dir=tmpdir,\n            max_epochs=1,\n            check_val_every_n_epoch=1.2,\n        )\n\n\ndef test_trainer_attach_data_pipeline_to_model(tmpdir):\n\n    class DataPipeline:\n\n        pass\n\n    class TestDataModule(LightningDataModule):\n\n        data_pipeline = DataPipeline()\n\n        def train_dataloader(self):\n            return DataLoader(RandomDataset(32, 64))\n\n        def val_dataloader(self):\n            return DataLoader(RandomDataset(32, 64))\n\n        def test_dataloader(self):\n            return DataLoader(RandomDataset(32, 64))\n\n    class TestCallback(Callback):\n\n        def on_fit_start(self, trainer, pl_module: LightningModule) -> None:\n            """Called when fit begins"""\n            assert isinstance(pl_module.data_pipeline, DataPipeline)\n\n    model = BoringModel()\n    dm = TestDataModule()\n\n    trainer = Trainer(default_root_dir=tmpdir, max_epochs=1, callbacks=[TestCallback()])\n    trainer.fit(model, datamodule=dm)\n\n\ndef test_exception_when_testing_or_validating_with_fast_dev_run(tmpdir):\n    trainer = Trainer(default_root_dir=tmpdir, fast_dev_run=True)\n\n    with pytest.raises(MisconfigurationException, match=r"\\.validate\\(\\)` with `fast_dev_run=True"):\n        trainer.validate()\n    with pytest.raises(MisconfigurationException, match=r"\\.test\\(\\)` with `fast_dev_run=True"):\n        trainer.test()\n',
        }
